test("issue comment command ids prefer control-plane comment ids", () => {
  assert.equal(
    issueCommentCommandId({ controlPlaneCommentId: "provider-42", giteaCommentId: "101" }, 7),
    "provider-42",
  );
  assert.equal(issueCommentCommandId({ giteaCommentId: "101" }, 7), "101");
  assert.equal(issueCommentCommandId({}, 7), "7");
});

test("issue comment source checks accept provider-neutral control-plane events", () => {
  assert.equal(isControlPlaneIssueComment({ kind: "issue_comment", source: "gitea" }), true);
  assert.equal(isControlPlaneIssueComment({ kind: "issue_comment", source: "control_plane" }), true);
  assert.equal(isControlPlaneIssueComment({ kind: "issue_comment", source: "native" }), false);
  assert.equal(isControlPlaneIssueComment({ kind: "run_comment", source: "control_plane" }), false);
});

