      const sync = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/issue-comments/sync?project=proj-a`, {
        method: "POST",
        headers: { "content-type": "application/json", authorization: "Bearer viewer-key" },
        body: JSON.stringify({ clientId: "issue-tab" }),
      });
      assert.equal(sync.status, 201);
      assert.deepEqual(requestedIssues, ["team/proj-a#42"]);
      const syncBody = await sync.json();
      assert.equal(syncBody.issue, "team/proj-a#42");
      assert.equal(syncBody.synced, 2);
      assert.deepEqual(syncBody.skipped, { duplicate: 0, loom: 1, empty: 1 });
      assert.equal(syncBody.events.length, 2);

      const repeat = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/issue-comments/sync?project=proj-a`, {
        method: "POST",
        headers: { "content-type": "application/json", authorization: "Bearer viewer-key" },
        body: JSON.stringify({ clientId: "issue-tab" }),
      });
      assert.equal(repeat.status, 200);
      const repeatBody = await repeat.json();
      assert.equal(repeatBody.synced, 0);
      assert.deepEqual(repeatBody.skipped, { duplicate: 2, loom: 1, empty: 1 });

      const events = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/events?project=proj-a`, {
        headers: { authorization: "Bearer viewer-key" },
      });
      assert.equal(events.status, 200);
      const eventBody = await events.json();
      const issueMessages = eventBody.filter((event: any) => event.type === "user_message" && event.data.kind === "issue_comment");
      assert.equal(issueMessages.length, 2);
      assert.deepEqual(issueMessages.map((event: any) => event.data.source), ["control_plane", "control_plane"]);
      assert.deepEqual(issueMessages.map((event: any) => event.data.controlPlaneProvider), ["gitea-forgejo", "gitea-forgejo"]);
      assert.deepEqual(issueMessages.map((event: any) => event.data.giteaCommentId), ["101", "102"]);
      assert.deepEqual(issueMessages.map((event: any) => event.data.controlPlaneCommentId), ["101", "102"]);
      assert.equal(issueMessages[0].data.controlPlaneCommentUrl, "http://git.local/team/proj-a/issues/42#comment-101");
      assert.equal(issueMessages[0].data.actor, "gitea:teammate");
      assert.equal(issueMessages[0].data.syncedByActor, "view-user");
      assert.equal(issueMessages[0].data.syncedByRole, "viewer");
      assert.equal(issueMessages[0].data.clientId, "issue-tab");

      const replay = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/replay?project=proj-a`, {
        headers: { authorization: "Bearer viewer-key" },
      });
