test("HTTP harness accepts signed Gitea issue comment webhooks into linked run logs", async () => {
  const workspaceRoot = await tempDir("loom-http-gitea-webhook");
  const secret = "hook-secret";

  await withServer(
    workspaceRoot,
    async (baseUrl) => {
      const create = await fetch(`${baseUrl}/runs`, {
        method: "POST",
        headers: { "content-type": "application/json", authorization: "Bearer dev-key" },
        body: JSON.stringify({
          tenant: "alice",
          project: "proj-a",
          issue: "team/proj-a#42",
          goal: "create webhook-steered run",
          script: [{ message: "finish", finish: true }],
          verify: [],
          skills: ["coding"],
        }),
      });
      assert.equal(create.status, 201);
      const summary = await create.json();
      const payload = JSON.stringify({
        action: "created",
        repository: { full_name: "team/proj-a" },
        issue: { number: 42 },
        comment: {
          id: 201,
          body: "Webhook steering note.",
          html_url: "http://git.local/team/proj-a/issues/42#comment-201",
          user: { login: "teammate" },
          created_at: "2026-06-26T11:00:00.000Z",
        },
      });

      const webhook = await fetch(`${baseUrl}/tenants/alice/webhooks/gitea/issue-comments?project=proj-a`, {
        method: "POST",
        headers: {
          "content-type": "application/json",
          "x-gitea-event": "issue_comment",
          "x-gitea-delivery": "delivery-1",
          "x-gitea-signature": hmacSha256(secret, payload),
        },
        body: payload,
      });
      assert.equal(webhook.status, 202);
      const webhookBody = await webhook.json();
      assert.equal(webhookBody.issue, "team/proj-a#42");
      assert.equal(webhookBody.synced, 1);
      assert.deepEqual(webhookBody.matchedRuns, [{ project: "proj-a", runId: summary.runId, synced: 1 }]);

      const duplicate = await fetch(`${baseUrl}/tenants/alice/webhooks/gitea/issue-comments?project=proj-a`, {
        method: "POST",
        headers: {
          "content-type": "application/json",
          "x-gitea-event": "issue_comment",
          "x-gitea-delivery": "delivery-1",
          "x-gitea-signature": hmacSha256(secret, payload),
        },
        body: payload,
      });
      assert.equal(duplicate.status, 200);
      assert.equal((await duplicate.json()).synced, 0);

      const invalid = await fetch(`${baseUrl}/tenants/alice/webhooks/gitea/issue-comments?project=proj-a`, {
        method: "POST",
        headers: {
          "content-type": "application/json",
          "x-gitea-event": "issue_comment",
          "x-gitea-signature": "bad-signature",
        },
        body: payload,
      });
      assert.equal(invalid.status, 401);

      const events = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/events?project=proj-a`, {
        headers: { authorization: "Bearer viewer-key" },
      });
      assert.equal(events.status, 200);
      const eventBody = await events.json();
      const webhookMessages = eventBody.filter((event: any) => event.type === "user_message" && event.data.kind === "issue_comment");
      assert.equal(webhookMessages.length, 1);
      assert.equal(webhookMessages[0].data.content, "Webhook steering note.");
      assert.equal(webhookMessages[0].data.giteaCommentId, "201");
      assert.equal(webhookMessages[0].data.actor, "gitea:teammate");
      assert.equal(webhookMessages[0].data.syncedByActor, "gitea-webhook");
      assert.equal(webhookMessages[0].data.deliveryId, "delivery-1");

      const audit = await fetch(`${baseUrl}/tenants/alice/audit?project=proj-a`, {
        headers: { authorization: "Bearer viewer-key" },
      });
      assert.equal(audit.status, 200);
      const auditBody = await audit.json();
      assert.ok(auditBody.some((event: any) =>
        event.type === "run_issue_comments_synced" &&
        event.actor === "gitea-webhook" &&
        event.role === "viewer" &&
        event.data.deliveryId === "delivery-1" &&
        event.data.controlPlaneProvider === "gitea-forgejo" &&
        event.data.controlPlaneCommentId === "201" &&
        event.data.controlPlaneCommentUrl === "http://git.local/team/proj-a/issues/42#comment-201" &&
        event.data.synced === 1
      ));
    },
    {
      giteaWebhookSecret: secret,
      tenantApiKeys: {
        alice: [
          { token: "dev-key", actor: "dev-user", role: "developer" },
          { token: "viewer-key", actor: "view-user", role: "viewer" },
        ],
      },
    },
  );
});

