test("HTTP harness fails a verified run when evaluator commands fail", async () => {
  const workspaceRoot = await tempDir("loom-http-evaluation-fail");

  await withServer(workspaceRoot, async (baseUrl) => {
    const create = await fetch(`${baseUrl}/runs`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        tenant: "alice",
        goal: "evaluate before review",
        script: [{ message: "finish", finish: true }],
        verify: ["true"],
        evaluate: ["printf http-evaluator-failed >&2; exit 9"],
        reviewRequired: true,
      }),
    });

    assert.equal(create.status, 201);
    const summary = await create.json();
    assert.equal(summary.status, "failed");
    assert.equal(summary.verification.ok, true);
    assert.equal(summary.evaluation.ok, false);
    assert.equal(summary.evaluation.exitCode, 9);
    assert.equal(summary.review, undefined);

    const readEvents = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/events`);
    assert.equal(readEvents.status, 200);
    const events = await readEvents.json();
    assert.ok(events.some((event: any) => event.type === "verification" && event.data.ok === true));
    assert.ok(events.some((event: any) => event.type === "evaluation" && event.data.ok === false));
    assert.equal(events.some((event: any) => event.type === "review_gate"), false);
  });
});

test("HTTP harness records tenant audit events and exposes an incremental feed", async () => {
  const workspaceRoot = await tempDir("loom-http-audit");
  let aliceRunId = "";

  await withServer(workspaceRoot, async (baseUrl) => {
    const createAlice = await fetch(`${baseUrl}/runs`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        tenant: "alice",
        goal: "create audited file",
        script: [{ message: "finish", finish: true }],
        verify: [],
        skills: ["coding"],
      }),
    });
    assert.equal(createAlice.status, 201);
    const alice = await createAlice.json();
    aliceRunId = alice.runId;

    const createAliceProject = await fetch(`${baseUrl}/runs`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        tenant: "alice",
        project: "proj-a",
        goal: "create project scoped audit",
        script: [{ message: "finish", finish: true }],
        verify: [],
        skills: ["coding"],
      }),
    });
    assert.equal(createAliceProject.status, 201);
    const aliceProject = await createAliceProject.json();

    const createBob = await fetch(`${baseUrl}/runs`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        tenant: "bob",
        goal: "create bob file",
        script: [{ message: "finish", finish: true }],
        verify: [],
        skills: ["coding"],
      }),
    });
    assert.equal(createBob.status, 201);

    const audit = await fetch(`${baseUrl}/tenants/alice/audit`);
    assert.equal(audit.status, 200);
    const events = await audit.json();
    assert.equal(events.length, 2);
    assert.equal(events[0].seq, 1);
    assert.equal(events[0].tenant, "alice");
    assert.equal(events[0].type, "run_created");
    assert.deepEqual(events[0].data, {
      project: "default",
      runId: aliceRunId,
      goal: "create audited file",
      status: "passed",
      async: false,
      queued: false,
    });

    assert.equal(events[1].tenant, "alice");
    assert.equal(events[1].data.project, "proj-a");
    assert.equal(events[1].data.runId, aliceProject.runId);

    const defaultAudit = await fetch(`${baseUrl}/tenants/alice/audit?project=default`);
    assert.equal(defaultAudit.status, 200);
    const defaultEvents = await defaultAudit.json();
    assert.deepEqual(defaultEvents.map((event: any) => event.data.project), ["default"]);
    assert.deepEqual(defaultEvents.map((event: any) => event.data.runId), [aliceRunId]);

    const projectAudit = await fetch(`${baseUrl}/tenants/alice/audit?project=proj-a`);
    assert.equal(projectAudit.status, 200);
    const projectEvents = await projectAudit.json();
    assert.deepEqual(projectEvents.map((event: any) => event.data.project), ["proj-a"]);
    assert.deepEqual(projectEvents.map((event: any) => event.data.runId), [aliceProject.runId]);

    const invalidProjectAudit = await fetch(`${baseUrl}/tenants/alice/audit?project=../proj-a`);
    assert.equal(invalidProjectAudit.status, 400);
    assert.match((await invalidProjectAudit.json()).error, /project/);

    const after = await fetch(`${baseUrl}/tenants/alice/audit?after=${events[0].seq}`);
    assert.equal(after.status, 200);
    assert.equal((await after.json()).length, 1);

    const auditStreamAbort = new AbortController();
    const auditStream = await fetch(`${baseUrl}/tenants/alice/audit/stream?after=0`, {
      headers: { "last-event-id": String(events[0].seq) },
      signal: auditStreamAbort.signal,
    });
    assert.equal(auditStream.status, 200);
    const auditReader = auditStream.body?.getReader();
    assert.ok(auditReader);
    const auditChunk = await auditReader.read();
    auditStreamAbort.abort();
    const auditStreamText = new TextDecoder().decode(auditChunk.value);
    assert.doesNotMatch(auditStreamText, /"seq":1/);
    assert.match(auditStreamText, /id: 2/);
  });

  await withServer(workspaceRoot, async (baseUrl) => {
    const audit = await fetch(`${baseUrl}/tenants/alice/audit`);
    assert.equal(audit.status, 200);
    const events = await audit.json();
    assert.equal(events.length, 2);
    assert.equal(events[0].tenant, "alice");
    assert.equal(events[0].data.runId, aliceRunId);
  });
});

test("HTTP harness tenant audit ignores unreadable and mismatched persisted audit lines", async () => {
  const workspaceRoot = await tempDir("loom-http-audit-corrupt");
  await mkdir(join(workspaceRoot, "alice", ".loom"), { recursive: true });
  await writeFile(
    join(workspaceRoot, "alice", ".loom", "audit.jsonl"),
    [
      JSON.stringify({
        tenant: "alice",
        seq: 1,
        ts: "2026-06-26T00:00:00.000Z",
        type: "project_created",
        data: { project: "proj-a" },
      }),
      "{not json",
      JSON.stringify({
        tenant: "bob",
        seq: 2,
        ts: "2026-06-26T00:00:01.000Z",
        type: "project_created",
        data: { project: "proj-b" },
      }),
      JSON.stringify({
        tenant: "alice",
        seq: 3,
        ts: "2026-06-26T00:00:02.000Z",
        type: "project_created",
        data: { project: "proj-c" },
      }),
      "",
    ].join("\n"),
    "utf8",
  );

  await withServer(workspaceRoot, async (baseUrl) => {
    const audit = await fetch(`${baseUrl}/tenants/alice/audit`);
    const auditText = await audit.text();
    assert.equal(audit.status, 200, auditText);
    const events = JSON.parse(auditText);
    assert.deepEqual(events.map((event) => [event.seq, event.tenant, event.data.project]), [
      [1, "alice", "proj-a"],
      [3, "alice", "proj-c"],
    ]);

    const after = await fetch(`${baseUrl}/tenants/alice/audit?after=1`);
    const afterText = await after.text();
    assert.equal(after.status, 200, afterText);
    assert.deepEqual(JSON.parse(afterText).map((event) => event.seq), [3]);

    const create = await fetch(`${baseUrl}/tenants/alice/projects`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ project: "proj-d" }),
    });
    assert.equal(create.status, 201);

    const appended = await fetch(`${baseUrl}/tenants/alice/audit?after=3`);
    assert.equal(appended.status, 200);
    const appendedEvents = await appended.json();
    assert.equal(appendedEvents.length, 1);
    assert.equal(appendedEvents[0].seq, 4);
    assert.equal(appendedEvents[0].data.project, "proj-d");
  });
});

test("HTTP harness records tenant audit events for workspace and run controls", async () => {
  const workspaceRoot = await tempDir("loom-http-audit-controls");
  await writeProjectRegistration(workspaceRoot, "alice", "proj-a");

  await withServer(
    workspaceRoot,
    async (baseUrl) => {
      const save = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/files`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ path: "notes.txt", content: "audit me\n", clientId: "wb-a" }),
      });
      assert.equal(save.status, 200);
      const savedFile = await save.json();

      const moveFile = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/files/move`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ fromPath: "notes.txt", toPath: "notes-renamed.txt", baseUpdatedAt: savedFile.updatedAt, clientId: "wb-a" }),
      });
      assert.equal(moveFile.status, 200);

      const deleteFile = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/files?path=notes-renamed.txt`, {
        method: "DELETE",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ clientId: "wb-a" }),
      });
      assert.equal(deleteFile.status, 200);

      const command = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/commands`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ command: "printf audit-command > command.txt", clientId: "wb-a" }),
      });
      assert.equal(command.status, 200);
      const commandBody = await command.json();

      const sessionResponse = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/sessions`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ command: "sh", clientId: "wb-a" }),
      });
      assert.equal(sessionResponse.status, 201);
      const session = await sessionResponse.json();
      const sessionInput = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/sessions/${session.sessionId}/input`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ input: "printf audit-input\n", clientId: "wb-a" }),
      });
      assert.equal(sessionInput.status, 200);
      const stopSession = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/sessions/${session.sessionId}/stop`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ clientId: "wb-a" }),
      });
      assert.equal(stopSession.status, 200);

      const reviewRun = await fetch(`${baseUrl}/runs`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({
          tenant: "alice",
          project: "proj-a",
          goal: "review audited run",
          script: [{ message: "finish", finish: true }],
          verify: [],
          skills: ["coding"],
          reviewRequired: true,
          clientId: "dash-a",
        }),
      });
      assert.equal(reviewRun.status, 201);
      const reviewSummary = await reviewRun.json();
      assert.equal(reviewSummary.status, "review_required");

      const review = await fetch(`${baseUrl}/tenants/alice/runs/${reviewSummary.runId}/review?project=proj-a`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ decision: "rejected", note: "needs changes", clientId: "dash-a" }),
      });
      assert.equal(review.status, 200);

      const deploymentRun = await fetch(`${baseUrl}/runs`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({
          tenant: "alice",
          project: "proj-a",
          goal: "deployment audited run",
          script: [{ message: "finish", finish: true }],
          verify: [],
          skills: ["coding"],
          deploymentRequired: true,
          clientId: "dash-a",
        }),
      });
      assert.equal(deploymentRun.status, 201);
      const deploymentSummary = await deploymentRun.json();
      assert.equal(deploymentSummary.status, "deployment_required");

      const deployment = await fetch(`${baseUrl}/tenants/alice/runs/${deploymentSummary.runId}/deployment?project=proj-a`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ decision: "approved", note: "ship it", clientId: "dash-a" }),
      });
      assert.equal(deployment.status, 200);

      const runningResponse = await fetch(`${baseUrl}/runs`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({
          tenant: "alice",
          project: "proj-a",
          async: true,
          goal: "cancel audited run",
          script: [
            {
              message: "sleep until cancelled",
              actions: [
                {
                  toolName: "shell.exec",
                  input: { command: "sleep 5; printf should-not-exist > cancelled.txt" },
                },
              ],
            },
            { message: "finish", finish: true },
          ],
          verify: ["test ! -f cancelled.txt"],
          skills: ["coding"],
          clientId: "dash-a",
        }),
      });
      assert.equal(runningResponse.status, 202);
      const running = await runningResponse.json();

      const cancel = await fetch(`${baseUrl}/tenants/alice/runs/${running.runId}/cancel?project=proj-a`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ reason: "audit cancel", clientId: "dash-a" }),
      });
      assert.equal(cancel.status, 200);

      const audit = await fetch(`${baseUrl}/tenants/alice/audit`);
      assert.equal(audit.status, 200);
      const events = await audit.json();
      assert.ok(events.some((event: any) => event.type === "workspace_file_written" && event.data.project === "proj-a" && event.data.path === "notes.txt" && event.data.bytes === 9 && event.data.clientId === "wb-a"));
      assert.ok(events.some((event: any) => event.type === "workspace_file_moved" && event.data.project === "proj-a" && event.data.fromPath === "notes.txt" && event.data.path === "notes-renamed.txt" && event.data.clientId === "wb-a"));
      assert.ok(events.some((event: any) => event.type === "workspace_file_deleted" && event.data.project === "proj-a" && event.data.path === "notes-renamed.txt" && event.data.clientId === "wb-a"));
      assert.ok(events.some((event: any) => event.type === "workspace_command_ran" && event.data.project === "proj-a" && event.data.commandId === commandBody.commandId && event.data.exitCode === 0 && event.data.clientId === "wb-a"));
      assert.ok(events.some((event: any) => event.type === "workspace_session_started" && event.data.project === "proj-a" && event.data.sessionId === session.sessionId && event.data.clientId === "wb-a"));
      assert.ok(events.some((event: any) => event.type === "workspace_session_input_sent" && event.data.project === "proj-a" && event.data.sessionId === session.sessionId && event.data.clientId === "wb-a"));
      assert.ok(events.some((event: any) => event.type === "workspace_session_stopped" && event.data.project === "proj-a" && event.data.sessionId === session.sessionId && event.data.clientId === "wb-a"));
      assert.ok(events.some((event: any) => event.type === "run_created" && event.data.project === "proj-a" && event.data.runId === reviewSummary.runId && event.data.clientId === "dash-a"));
      assert.ok(events.some((event: any) => event.type === "review_decided" && event.data.project === "proj-a" && event.data.runId === reviewSummary.runId && event.data.decision === "rejected" && event.data.clientId === "dash-a"));
      assert.ok(events.some((event: any) => event.type === "run_created" && event.data.project === "proj-a" && event.data.runId === deploymentSummary.runId && event.data.clientId === "dash-a"));
      assert.ok(events.some((event: any) => event.type === "deployment_decided" && event.data.project === "proj-a" && event.data.runId === deploymentSummary.runId && event.data.decision === "approved" && event.data.clientId === "dash-a"));
      assert.ok(events.some((event: any) => event.type === "run_created" && event.data.project === "proj-a" && event.data.runId === running.runId && event.data.clientId === "dash-a"));
      assert.ok(events.some((event: any) => event.type === "run_cancelled" && event.data.project === "proj-a" && event.data.runId === running.runId && event.data.reason === "audit cancel" && event.data.clientId === "dash-a"));

      const projectsResponse = await fetch(`${baseUrl}/tenants/alice/projects`);
      const projectsText = await projectsResponse.text();
      assert.equal(projectsResponse.status, 200, projectsText);
      const projectSummary = JSON.parse(projectsText).find((project: any) => project.project === "proj-a");
      assert.equal(projectSummary.latestWorkspaceActivity.type, "workspace_file_deleted");
      assert.equal(projectSummary.latestWorkspaceActivity.path, "notes-renamed.txt");
      assert.equal(projectSummary.latestWorkspaceActivity.clientId, "wb-a");
      assert.ok(projectSummary.activityAt >= projectSummary.latestWorkspaceActivity.ts);
      assert.equal(projectSummary.latestControlActivity.type, "run_cancelled");
      assert.equal(projectSummary.latestControlActivity.runId, running.runId);
      assert.equal(projectSummary.latestControlActivity.status, "cancelled");
      assert.equal(projectSummary.latestControlActivity.reason, "audit cancel");
      assert.equal(projectSummary.latestControlActivity.clientId, "dash-a");
      assert.ok(projectSummary.activityAt >= projectSummary.latestControlActivity.ts);

      const projectDetailResponse = await fetch(`${baseUrl}/tenants/alice/projects/proj-a`);
      const projectDetailText = await projectDetailResponse.text();
      assert.equal(projectDetailResponse.status, 200, projectDetailText);
      const projectDetail = JSON.parse(projectDetailText);
      assert.equal(projectDetail.latestWorkspaceActivity.type, "workspace_file_deleted");
      assert.equal(projectDetail.latestWorkspaceActivity.path, "notes-renamed.txt");
      assert.equal(projectDetail.latestControlActivity.type, "run_cancelled");
      assert.equal(projectDetail.latestControlActivity.runId, running.runId);
      assert.equal(projectDetail.latestControlActivity.reason, "audit cancel");
    },
    { allowedTools: ["file.read", "file.write", "shell.exec", "git.diff", "verify.run"] },
  );
});

test("HTTP harness breaks project workspace activity timestamp ties by audit seq", async () => {
  const workspaceRoot = await tempDir("loom-http-project-activity-tie");
  await writeProjectRegistration(workspaceRoot, "alice", "proj-a");
  await mkdir(join(workspaceRoot, "alice", ".loom"), { recursive: true });
  await writeFile(
    join(workspaceRoot, "alice", ".loom", "audit.jsonl"),
    [
      JSON.stringify({
        tenant: "alice",
        seq: 2,
        ts: "2026-06-27T00:00:00.000Z",
        type: "workspace_file_deleted",
        data: { project: "proj-a", path: "second.txt" },
      }),
      JSON.stringify({
        tenant: "alice",
        seq: 1,
        ts: "2026-06-27T00:00:00.000Z",
        type: "workspace_file_written",
        data: { project: "proj-a", path: "first.txt", bytes: 5 },
      }),
      "",
    ].join("\n"),
    "utf8",
  );

  await withServer(workspaceRoot, async (baseUrl) => {
    const projects = await fetch(`${baseUrl}/tenants/alice/projects`);
    const text = await projects.text();
    assert.equal(projects.status, 200, text);
    const project = JSON.parse(text).find((item: any) => item.project === "proj-a");
    assert.equal(project.latestWorkspaceActivity.type, "workspace_file_deleted");
    assert.equal(project.latestWorkspaceActivity.path, "second.txt");
  });
});

test("HTTP harness gates deployable runs behind admin deployment approval", async () => {
  const workspaceRoot = await tempDir("loom-http-deployment-gate");

  await withServer(
    workspaceRoot,
    async (baseUrl) => {
      const create = await fetch(`${baseUrl}/runs`, {
        method: "POST",
        headers: { "content-type": "application/json", authorization: "Bearer dev-key" },
        body: JSON.stringify({
          tenant: "alice",
          project: "prod",
          goal: "prepare production change",
          script: [{ message: "finish", finish: true }],
          verify: [],
          skills: ["coding"],
          deploymentRequired: true,
        }),
      });
      assert.equal(create.status, 201);
      const summary = await create.json();
      assert.equal(summary.status, "deployment_required");
      assert.deepEqual(summary.deployment, { required: true, status: "pending" });

      const developerDecision = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/deployment?project=prod`, {
        method: "POST",
        headers: { "content-type": "application/json", authorization: "Bearer dev-key" },
        body: JSON.stringify({ decision: "approved", note: "developer cannot ship prod" }),
      });
      assert.equal(developerDecision.status, 403);
      assert.match((await developerDecision.json()).error, /requires admin/);

      const approve = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/deployment?project=prod`, {
        method: "POST",
        headers: { "content-type": "application/json", authorization: "Bearer admin-key" },
        body: JSON.stringify({ decision: "approved", note: "approved for prod", clientId: "dash-deploy" }),
      });
      assert.equal(approve.status, 200);
      const approved = await approve.json();
      assert.equal(approved.status, "passed");
      assert.deepEqual(approved.deployment, { required: true, status: "approved", note: "approved for prod" });

      const events = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/events?project=prod`, {
        headers: { authorization: "Bearer viewer-key" },
      });
      assert.equal(events.status, 200);
      const eventBody = await events.json();
      assert.ok(eventBody.some((event: any) => event.type === "deployment_gate" && event.data.status === "pending"));
      assert.ok(eventBody.some((event: any) => event.type === "deployment_gate" && event.data.status === "approved"));
      const approvedDeploymentEvent = eventBody.find((event: any) => event.type === "deployment_gate" && event.data.status === "approved");
      assert.equal(approvedDeploymentEvent?.data.actor, "admin-user");
      assert.equal(approvedDeploymentEvent?.data.role, "admin");
      assert.equal(approvedDeploymentEvent?.data.clientId, "dash-deploy");
      assert.ok(eventBody.some((event: any) => event.type === "finish" && event.data.status === "deployment_required"));
      assert.ok(eventBody.some((event: any) => event.type === "finish" && event.data.status === "passed"));

      const replay = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/replay?project=prod`, {
        headers: { authorization: "Bearer viewer-key" },
      });
      assert.equal(replay.status, 200);
      const replayBody = await replay.json();
      const deploymentEntry = replayBody.timeline.find((entry: any) => entry.type === "deployment_gate" && entry.status === "approved");
      assert.equal(deploymentEntry?.actor, "admin-user");
      assert.equal(deploymentEntry?.role, "admin");
      assert.equal(deploymentEntry?.clientId, "dash-deploy");

      const audit = await fetch(`${baseUrl}/tenants/alice/audit`, {
        headers: { authorization: "Bearer viewer-key" },
      });
      assert.equal(audit.status, 200);
      const auditEvents = await audit.json();
      assert.ok(auditEvents.some((event: any) => event.type === "deployment_decided" && event.actor === "admin-user" && event.role === "admin" && event.data.runId === summary.runId && event.data.status === "passed"));
      assert.ok(auditEvents.every((event: any) => !JSON.stringify(event).includes("admin-key") && !JSON.stringify(event).includes("dev-key") && !JSON.stringify(event).includes("viewer-key")));
    },
    {
      tenantApiKeys: {
        alice: [
          { token: "admin-key", actor: "admin-user", role: "admin" },
          { token: "dev-key", actor: "dev-user", role: "developer" },
          { token: "viewer-key", actor: "view-user", role: "viewer" },
        ],
      },
    },
  );
});

test("HTTP harness can decide deployment-gated runs from authorized Gitea issue comments", async () => {
  const workspaceRoot = await tempDir("loom-http-deployment-gitea");
  const secret = "hook-secret";

  await withServer(
    workspaceRoot,
    async (baseUrl) => {
      const create = await fetch(`${baseUrl}/runs`, {
        method: "POST",
        headers: { "content-type": "application/json", authorization: "Bearer dev-key" },
        body: JSON.stringify({
          tenant: "alice",
          project: "prod",
          issue: "team/prod#50",
          goal: "deploy from linked issue comment",
          script: [{ message: "finish", finish: true }],
          verify: [],
          skills: ["coding"],
          deploymentRequired: true,
        }),
      });
      assert.equal(create.status, 201);
      const summary = await create.json();
      assert.equal(summary.status, "deployment_required");

      const deniedPayload = JSON.stringify({
        action: "created",
        repository: { full_name: "team/prod" },
        issue: { number: 50 },
        comment: {
          id: 901,
          body: "/loom approve-deploy\nShip it.",
          html_url: "http://git.local/team/prod/issues/50#comment-901",
          user: { login: "deployer" },
        },
      });
      const denied = await fetch(`${baseUrl}/tenants/alice/webhooks/gitea/issue-comments?project=prod`, {
        method: "POST",
        headers: {
          "content-type": "application/json",
          "x-gitea-event-type": "issue_comment",
          "x-gitea-delivery": "delivery-deploy-denied",
          "x-gitea-signature": hmacSha256(secret, deniedPayload),
        },
        body: deniedPayload,
      });
      assert.equal(denied.status, 202);
      assert.deepEqual((await denied.json()).matchedRuns, [{
        project: "prod",
        runId: summary.runId,
        synced: 1,
        deploymentRequested: 1,
        deploymentDenied: 1,
      }]);

      const stillPending = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}?project=prod`, {
        headers: { authorization: "Bearer viewer-key" },
      });
      assert.equal(stillPending.status, 200);
      assert.equal((await stillPending.json()).status, "deployment_required");

      const approvedPayload = JSON.stringify({
        action: "created",
        repository: { full_name: "team/prod" },
        issue: { number: 50 },
        comment: {
          id: 902,
          body: "/loom approve-deploy\nApproved for prod.",
          html_url: "http://git.local/team/prod/issues/50#comment-902",
          user: { login: "ops" },
        },
      });
      const approved = await fetch(`${baseUrl}/tenants/alice/webhooks/gitea/issue-comments?project=prod`, {
        method: "POST",
        headers: {
          "content-type": "application/json",
          "x-gitea-event-type": "issue_comment",
          "x-gitea-delivery": "delivery-deploy-approved",
          "x-gitea-signature": hmacSha256(secret, approvedPayload),
        },
        body: approvedPayload,
      });
      assert.equal(approved.status, 202);
      assert.deepEqual((await approved.json()).matchedRuns, [{
        project: "prod",
        runId: summary.runId,
        synced: 1,
        deploymentRequested: 1,
        deployed: 1,
      }]);

      const deployed = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}?project=prod`, {
        headers: { authorization: "Bearer viewer-key" },
      });
      assert.equal(deployed.status, 200);
      const deployedBody = await deployed.json();
      assert.equal(deployedBody.status, "passed");
      assert.deepEqual(deployedBody.deployment, { required: true, status: "approved", note: "Approved for prod." });

      const rejectCreate = await fetch(`${baseUrl}/runs`, {
        method: "POST",
        headers: { "content-type": "application/json", authorization: "Bearer dev-key" },
        body: JSON.stringify({
          tenant: "alice",
          project: "prod",
          issue: "team/prod#51",
          goal: "reject deployment from issue comment",
          script: [{ message: "finish", finish: true }],
          verify: [],
          skills: ["coding"],
          deploymentRequired: true,
        }),
      });
      assert.equal(rejectCreate.status, 201);
      const rejectSummary = await rejectCreate.json();
      assert.equal(rejectSummary.status, "deployment_required");

      const rejectedPayload = JSON.stringify({
        action: "created",
        repository: { full_name: "team/prod" },
        issue: { number: 51 },
        comment: {
          id: 903,
          body: "/loom reject-deploy\nHold production.",
          html_url: "http://git.local/team/prod/issues/51#comment-903",
          user: { login: "ops" },
        },
      });
      const rejected = await fetch(`${baseUrl}/tenants/alice/webhooks/gitea/issue-comments?project=prod`, {
        method: "POST",
        headers: {
          "content-type": "application/json",
          "x-gitea-event-type": "issue_comment",
          "x-gitea-delivery": "delivery-deploy-rejected",
          "x-gitea-signature": hmacSha256(secret, rejectedPayload),
        },
        body: rejectedPayload,
      });
      assert.equal(rejected.status, 202);
      assert.deepEqual((await rejected.json()).matchedRuns, [{
        project: "prod",
        runId: rejectSummary.runId,
        synced: 1,
        deploymentRequested: 1,
        deployed: 1,
      }]);

      const rejectedRead = await fetch(`${baseUrl}/tenants/alice/runs/${rejectSummary.runId}?project=prod`, {
        headers: { authorization: "Bearer viewer-key" },
      });
      assert.equal(rejectedRead.status, 200);
      const rejectedBody = await rejectedRead.json();
      assert.equal(rejectedBody.status, "failed");
      assert.deepEqual(rejectedBody.deployment, { required: true, status: "rejected", note: "Hold production." });

      const olderPendingCreate = await fetch(`${baseUrl}/runs`, {
        method: "POST",
        headers: { "content-type": "application/json", authorization: "Bearer dev-key" },
        body: JSON.stringify({
          tenant: "alice",
          project: "prod",
          issue: "team/prod#52",
          goal: "older pending deployment on same issue",
          script: [{ message: "finish", finish: true }],
          verify: [],
          skills: ["coding"],
          deploymentRequired: true,
        }),
      });
      assert.equal(olderPendingCreate.status, 201);
      const olderPending = await olderPendingCreate.json();

      const latestPendingCreate = await fetch(`${baseUrl}/runs`, {
        method: "POST",
        headers: { "content-type": "application/json", authorization: "Bearer dev-key" },
        body: JSON.stringify({
          tenant: "alice",
          project: "prod",
          issue: "team/prod#52",
          goal: "latest pending deployment on same issue",
          script: [{ message: "finish", finish: true }],
          verify: [],
          skills: ["coding"],
          deploymentRequired: true,
        }),
      });
      assert.equal(latestPendingCreate.status, 201);
      const latestPending = await latestPendingCreate.json();

      const latestOnlyPayload = JSON.stringify({
        action: "created",
        repository: { full_name: "team/prod" },
        issue: { number: 52 },
        comment: {
          id: 904,
          body: "/loom approve-deploy\nLatest only.",
          html_url: "http://git.local/team/prod/issues/52#comment-904",
          user: { login: "ops" },
        },
      });
      const latestOnly = await fetch(`${baseUrl}/tenants/alice/webhooks/gitea/issue-comments?project=prod`, {
        method: "POST",
        headers: {
          "content-type": "application/json",
          "x-gitea-event-type": "issue_comment",
          "x-gitea-delivery": "delivery-deploy-latest-only",
          "x-gitea-signature": hmacSha256(secret, latestOnlyPayload),
        },
        body: latestOnlyPayload,
      });
      assert.equal(latestOnly.status, 202);
      assert.deepEqual((await latestOnly.json()).matchedRuns, [
        {
          project: "prod",
          runId: latestPending.runId,
          synced: 1,
          deploymentRequested: 1,
          deployed: 1,
        },
        {
          project: "prod",
          runId: olderPending.runId,
          synced: 1,
        },
      ]);

      const latestRead = await fetch(`${baseUrl}/tenants/alice/runs/${latestPending.runId}?project=prod`, {
        headers: { authorization: "Bearer viewer-key" },
      });
      assert.equal(latestRead.status, 200);
      assert.equal((await latestRead.json()).status, "passed");
      const olderRead = await fetch(`${baseUrl}/tenants/alice/runs/${olderPending.runId}?project=prod`, {
        headers: { authorization: "Bearer viewer-key" },
      });
      assert.equal(olderRead.status, 200);
      assert.equal((await olderRead.json()).status, "deployment_required");

      const syncOlderCreate = await fetch(`${baseUrl}/runs`, {
        method: "POST",
        headers: { "content-type": "application/json", authorization: "Bearer dev-key" },
        body: JSON.stringify({
          tenant: "alice",
          project: "prod",
          issue: "team/prod#53",
          goal: "run-scoped deployment sync older",
          script: [{ message: "finish", finish: true }],
          verify: [],
          skills: ["coding"],
          deploymentRequired: true,
        }),
      });
      assert.equal(syncOlderCreate.status, 201);
      const syncOlder = await syncOlderCreate.json();

      const syncLatestCreate = await fetch(`${baseUrl}/runs`, {
        method: "POST",
        headers: { "content-type": "application/json", authorization: "Bearer dev-key" },
        body: JSON.stringify({
          tenant: "alice",
          project: "prod",
          issue: "team/prod#53",
          goal: "run-scoped deployment sync latest",
          script: [{ message: "finish", finish: true }],
          verify: [],
          skills: ["coding"],
          deploymentRequired: true,
        }),
      });
      assert.equal(syncLatestCreate.status, 201);
      const syncLatest = await syncLatestCreate.json();

      const sync = await fetch(`${baseUrl}/tenants/alice/runs/${syncOlder.runId}/issue-comments/sync?project=prod`, {
        method: "POST",
        headers: { "content-type": "application/json", authorization: "Bearer viewer-key" },
        body: JSON.stringify({ clientId: "deploy-sync-tab" }),
      });
      assert.equal(sync.status, 201);
      const syncBody = await sync.json();
      assert.equal(syncBody.synced, 1);
      assert.equal(syncBody.deploymentRequested, 1);
      assert.equal(syncBody.deployed, 1);
      assert.equal(syncBody.deploymentDenied, 0);

      const syncOlderRead = await fetch(`${baseUrl}/tenants/alice/runs/${syncOlder.runId}?project=prod`, {
        headers: { authorization: "Bearer viewer-key" },
      });
      assert.equal(syncOlderRead.status, 200);
      assert.equal((await syncOlderRead.json()).status, "passed");
      const syncLatestRead = await fetch(`${baseUrl}/tenants/alice/runs/${syncLatest.runId}?project=prod`, {
        headers: { authorization: "Bearer viewer-key" },
      });
      assert.equal(syncLatestRead.status, 200);
      assert.equal((await syncLatestRead.json()).status, "deployment_required");

      const events = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/events?project=prod`, {
        headers: { authorization: "Bearer viewer-key" },
      });
      assert.equal(events.status, 200);
      const eventBody = await events.json();
      const deployCommand = eventBody.find((event: any) => event.type === "user_message" && event.data.giteaCommentId === "902");
      assert.equal(deployCommand.data.deploymentRequested, true);
      assert.equal(deployCommand.data.deploymentDecision, "approved");
      assert.equal(deployCommand.data.deploymentNote, "Approved for prod.");
      assert.ok(eventBody.some((event: any) =>
        event.type === "deployment_gate" &&
        event.data.status === "approved" &&
        event.data.actor === "gitea:ops" &&
        event.data.role === "admin"
      ));

      const audit = await fetch(`${baseUrl}/tenants/alice/audit?project=prod`, {
        headers: { authorization: "Bearer viewer-key" },
      });
      assert.equal(audit.status, 200);
      const auditBody = await audit.json();
      assert.ok(auditBody.some((event: any) =>
        event.type === "deployment_decided" &&
        event.actor === "gitea:ops" &&
        event.role === "admin" &&
        event.data.runId === summary.runId &&
        event.data.decision === "approved" &&
        event.data.note === "Approved for prod."
      ));
      assert.ok(auditBody.some((event: any) =>
        event.type === "deployment_decided" &&
        event.actor === "gitea:ops" &&
        event.data.runId === rejectSummary.runId &&
        event.data.decision === "rejected" &&
        event.data.note === "Hold production."
      ));
    },
    {
      giteaWebhookSecret: secret,
      issueCommentReader: async (issue: string) => {
        if (issue !== "team/prod#53") return [];
        return [{
          id: 905,
          body: "/loom approve-deploy\nRun-scoped deploy approval.",
          author: "ops",
          url: "http://git.local/team/prod/issues/53#comment-905",
          createdAt: "2026-06-27T00:00:00.000Z",
        }];
      },
      tenantApiKeys: {
        alice: [
          { token: "admin-key", actor: "admin-user", role: "admin" },
          { token: "dev-key", actor: "dev-user", role: "developer" },
          { token: "viewer-key", actor: "view-user", role: "viewer" },
          { token: "ops-key", actor: "gitea:ops", role: "admin" },
          { token: "deployer-key", actor: "gitea:deployer", role: "developer" },
        ],
      },
    },
  );
});

test("HTTP harness routes approved reviews into the deployment gate", async () => {
  const workspaceRoot = await tempDir("loom-http-review-deployment-gate");

  await withServer(
    workspaceRoot,
    async (baseUrl) => {
      const create = await fetch(`${baseUrl}/runs`, {
        method: "POST",
        headers: { "content-type": "application/json", authorization: "Bearer dev-key" },
        body: JSON.stringify({
          tenant: "alice",
          project: "prod",
          goal: "review then deploy",
          script: [{ message: "finish", finish: true }],
          verify: [],
          skills: ["coding"],
          reviewRequired: true,
          deploymentRequired: true,
        }),
      });
      assert.equal(create.status, 201);
      const summary = await create.json();
      assert.equal(summary.status, "review_required");
      assert.deepEqual(summary.review, { required: true, status: "pending" });
      assert.deepEqual(summary.deployment, { required: true, status: "pending" });

      const review = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/review?project=prod`, {
        method: "POST",
        headers: { "content-type": "application/json", authorization: "Bearer dev-key" },
        body: JSON.stringify({ decision: "approved", note: "review ok", clientId: "dash-review" }),
      });
      assert.equal(review.status, 200);
      const reviewed = await review.json();
      assert.equal(reviewed.status, "deployment_required");
      assert.deepEqual(reviewed.review, { required: true, status: "approved", note: "review ok" });
      assert.deepEqual(reviewed.deployment, { required: true, status: "pending" });

      const events = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/events?project=prod`, {
        headers: { authorization: "Bearer dev-key" },
      });
      assert.equal(events.status, 200);
      const body = await events.json();
      const approvedReviewEvent = body.find((event: any) => event.type === "review_gate" && event.data.status === "approved");
      assert.equal(approvedReviewEvent?.data.actor, "dev-user");
      assert.equal(approvedReviewEvent?.data.role, "developer");
      assert.equal(approvedReviewEvent?.data.clientId, "dash-review");
    },
    {
      tenantApiKeys: {
        alice: [
          { token: "admin-key", actor: "admin-user", role: "admin" },
          { token: "dev-key", actor: "dev-user", role: "developer" },
        ],
      },
    },
  );
});

test("HTTP harness appends final finish event after review approval", async () => {
  const workspaceRoot = await tempDir("loom-http-review-final-finish");

  await withServer(workspaceRoot, async (baseUrl) => {
    const create = await fetch(`${baseUrl}/runs`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        tenant: "alice",
        goal: "review final finish",
        script: [{ message: "finish", finish: true }],
        verify: [],
        reviewRequired: true,
      }),
    });
    assert.equal(create.status, 201);
    const created = await create.json();
    assert.equal(created.status, "review_required");

    const review = await fetch(`${baseUrl}/tenants/alice/runs/${created.runId}/review`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ decision: "approved" }),
    });
    assert.equal(review.status, 200);
    assert.equal((await review.json()).status, "passed");

    const events = await fetch(`${baseUrl}/tenants/alice/runs/${created.runId}/events`);
    assert.equal(events.status, 200);
    const body = await events.json();
    assert.ok(body.some((event: any) => event.type === "finish" && event.data.status === "review_required"));
    assert.ok(body.some((event: any) => event.type === "finish" && event.data.status === "passed"));
  });
});

test("HTTP harness rejects oversized run request bodies with 413", async () => {
  const workspaceRoot = await tempDir("loom-http-large-run-body");

  await withServer(workspaceRoot, async (baseUrl) => {
    const create = await fetch(`${baseUrl}/runs`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ tenant: "alice", goal: "x".repeat(1_000_001) }),
    });

    assert.equal(create.status, 413);
    assert.match((await create.json()).error, /request body too large/);
  });
});

