test("HTTP harness status reports platform readiness for agent-git-service provider", async () => {
  const workspaceRoot = await tempDir("loom-http-platform-readiness-agent-git-service-ok");
  const discoveryRequests: string[] = [];
  const agentGitService = createServer((req, res) => {
    discoveryRequests.push(req.url ?? "");
    res.writeHead(200, { "content-type": "application/json" });
    res.end(JSON.stringify({ ok: true }));
  });
  await new Promise<void>((resolve) => agentGitService.listen(0, "127.0.0.1", resolve));
  const address = agentGitService.address();
  assert.equal(typeof address, "object");
  assert.ok(address);
  const controlPlaneBaseUrl = `http://127.0.0.1:${address.port}/api/v3`;

  try {
    await withServer(
      workspaceRoot,
      async (baseUrl) => {
      const response = await fetch(`${baseUrl}/status`, {
        headers: { authorization: "Bearer admin-key" },
      });
      assert.equal(response.status, 200);
      const body = await response.json();

      assert.deepEqual({ ...body.server.controlPlane, discovery: undefined }, {
        ...expectedControlPlane("agent-git-service"),
        discovery: undefined,
      });
      assert.deepEqual(body.server.controlPlane.discovery, {
        ok: true,
        baseUrl: controlPlaneBaseUrl,
        endpointCount: 3,
        okEndpointCount: 3,
        missingEndpoints: [],
        tokenMode: "admin",
        tenantCount: 0,
        tenantOkCount: 0,
        missingTenants: [],
        endpoints: [
          { endpoint: "/api/v3", url: controlPlaneBaseUrl, ok: true, status: 200 },
          { endpoint: "/api/v3/meta", url: `${controlPlaneBaseUrl}/meta`, ok: true, status: 200 },
          { endpoint: "/api/v3/rate_limit", url: `${controlPlaneBaseUrl}/rate_limit`, ok: true, status: 200 },
        ],
      });
      assert.equal(body.readiness.ok, true);
      assert.deepEqual(body.readiness.checks.controlPlaneDiscovery, {
        required: true,
        ok: true,
        provider: "agent-git-service",
        baseUrlConfigured: true,
        endpointCount: 3,
        okEndpointCount: 3,
        missingEndpoints: [],
        tokenMode: "admin",
        tenantCount: 0,
        tenantOkCount: 0,
        missingTenants: [],
      });
      assert.equal(body.readiness.checks.controlPlanePullRequest.provider, "agent-git-service");
      assert.equal(body.readiness.checks.controlPlaneMerge.provider, "agent-git-service");
      assert.equal(body.readiness.checks.controlPlaneIssueComments.provider, "agent-git-service");
      assert.equal(body.readiness.checks.controlPlaneIssueUrl.provider, "agent-git-service");
      assert.equal(body.readiness.checks.controlPlaneSignedWebhooks.provider, "agent-git-service");
      assert.equal(body.readiness.checks.controlPlaneGitTransport.provider, "agent-git-service");
      assert.equal(body.readiness.checks.controlPlaneGitTransport.sampleRepo, "team/smoke");
      assert.equal(body.readiness.checks.controlPlaneGitTransport.sampleRemoteUrl, `http://127.0.0.1:${address.port}/team/smoke.git`);
      assert.deepEqual(body.readiness.checks.controlPlaneWorkspaceBranchLease, {
        required: true,
        ok: true,
        provider: "agent-git-service",
        runWorkspaceIsolation: "run",
        branchDerivation: "run-suffixed",
        activeRunLeaseEvidence: true,
      });
      assert.equal(body.readiness.checks.controlPlaneAgentIdentity.provider, "agent-git-service");
      assert.equal(body.readiness.checks.controlPlaneBackupRestoreMigration.provider, "agent-git-service");
    },
      {
      profile: "platform-readiness",
      controlPlaneProvider: "agent-git-service",
      controlPlaneBaseUrl,
      controlPlaneAdminToken: "admin-token",
      executorKind: "coder",
      runWorkspaceIsolation: "run",
      allowedTools: [...ONLINE_SANDBOX_REQUIRED_SERVER_TOOLS, "git.pr"],
      modelBaseUrl: "https://model.example",
      modelApiKey: "model-key",
      issueBaseUrl: controlPlaneBaseUrl,
      brainSignalIngest: () => undefined,
      pullRequestReporter: async () => undefined,
      workspacePullRequestReporter: async () => undefined,
      mergeReporter: async () => undefined,
      issueCommentReader: async () => [],
      giteaWebhookSecret: "webhook-secret",
      controlPlaneAgentIdentity: {
        mode: "tenant-scoped",
        tenants: ["alice"],
      },
      tenantApiKeys: {
        alice: [
          { token: "admin-key", actor: "ops", role: "admin" },
          { token: "dev-key", actor: "eno", role: "developer" },
          { token: "viewer-key", actor: "auditor", role: "viewer" },
        ],
      },
      createExecutor: (_cwd: string, context: { runId: string }) => fakeSessionExecutor([], context.runId),
      },
    );
  } finally {
    await new Promise<void>((resolve, reject) =>
      agentGitService.close((error) => (error ? reject(error) : resolve())),
    );
  }
  assert.deepEqual(discoveryRequests.sort(), ["/api/v3", "/api/v3/meta", "/api/v3/rate_limit"]);
});

