test("HTTP harness activates AGS cockpit queue backend when a queue repo is configured", async () => {
  const workspaceRoot = await tempDir("loom-http-operator-cockpit-queue-ags-backend-active");
  const agentGitService = await startAgentGitServiceContractServer();

  try {
    await withServer(
      workspaceRoot,
      async (baseUrl) => {
        const tenantStatus = await fetch(`${baseUrl}/tenants/alice/status`, {
          headers: { authorization: "Bearer viewer-key" },
        });
        assert.equal(tenantStatus.status, 200);
        const tenantStatusBody = await tenantStatus.json();
        assert.equal(tenantStatusBody.server.concurrencyAdmission.operatorCockpitQueue.requestedBackend, "agent-git-service");
        assert.equal(tenantStatusBody.server.concurrencyAdmission.operatorCockpitQueue.activeBackend, "agent-git-service");
        assert.equal("fallbackReason" in tenantStatusBody.server.concurrencyAdmission.operatorCockpitQueue, false);

        const executionStatus = await fetch(`${baseUrl}/tenants/alice/operator/cockpit-execution-status`, {
          headers: { authorization: "Bearer admin-key" },
        });
        assert.equal(executionStatus.status, 200);
        const executionStatusBody = await executionStatus.json();
        assert.deepEqual(executionStatusBody.coordination.store, {
          kind: "agent-git-service-contents",
          repo: "team/loom-ops",
          path: ".loom/operator-cockpit-queue/store.json",
        });
        const contentsRequests = agentGitService.requests.filter((request) =>
          request.path === "/api/v3/repos/team/loom-ops/contents/.loom/operator-cockpit-queue/store.json",
        );
        assert.ok(contentsRequests.some((request) => request.method === "GET"));
        assert.equal(contentsRequests[0]?.authorization, "Bearer admin-token");
      },
      {
        profile: "platform-readiness",
        controlPlaneProvider: "agent-git-service",
        controlPlaneBaseUrl: agentGitService.baseUrl,
        controlPlaneAdminToken: "admin-token",
        operatorCockpitQueueBackend: "agent-git-service",
        operatorCockpitQueueAgentGitServiceRepo: "team/loom-ops",
        tenantApiKeys: {
          alice: [
            { token: "admin-key", actor: "ops", role: "admin" },
            { token: "viewer-key", actor: "auditor", role: "viewer" },
          ],
        },
      },
    );
  } finally {
    await agentGitService.close();
  }
});

