test("dashboard project concurrency board sorts pressure and preserves selected project", () => {
  const harness = createDashboardProjectConcurrencyHarness();
  harness.state.tenantPolicy = { limits: { maxActiveRuns: 1 } };
  harness.state.projects = [
    {
      project: "z-active",
      runCount: 1,
      activeWorkspaceSessions: 1,
      concurrency: {
        state: "active",
        activeRunDetails: [{
          tenant: "alice",
          project: "z-active",
          runId: "run-z",
          workspaceLeaseScope: "run",
          workspaceLeaseKey: "alice/z-active/run-z",
        }],
      },
    },
    {
      project: "b-queued",
      runCount: 2,
      queuedRunCount: 1,
      queuedRuns: [{
        tenant: "alice",
        project: "b-queued",
        runId: "run-b",
        blockedReason: "tenant_active_run_limit",
        limit: 1,
        tenantQueuePosition: 1,
        projectQueuePosition: 1,
      }],
      concurrency: { state: "queued" },
    },
    {
      project: "a-contended",
      runCount: 3,
      queuedRunCount: 2,
      runningRunId: "run-a",
      workspaceConflictCount: 1,
      concurrency: { state: "contended" },
    },
    {
      project: "ignored-idle",
      runCount: 0,
    },
  ];
  harness.projectInput.value = "b-queued";

  harness.renderProjects();

  assert.match(harness.board.innerHTML, /<h3>Project Concurrency<\/h3>/);
  assert.match(harness.board.innerHTML, /3 active/);
  assert.match(harness.board.innerHTML, /1 contended/);
  assert.match(harness.board.innerHTML, /1 queued/);
  assert.match(harness.board.innerHTML, /1 active work/);
  assert.ok(harness.board.innerHTML.indexOf("a-contended") < harness.board.innerHTML.indexOf("b-queued"));
  assert.ok(harness.board.innerHTML.indexOf("b-queued") < harness.board.innerHTML.indexOf("z-active"));
  assert.equal(harness.board.innerHTML.includes("ignored-idle"), false);
  assert.match(harness.board.innerHTML, /data-project-active-run-id="run-z"/);
  assert.match(harness.board.innerHTML, /data-project-active-run-pause-id="run-z"/);
  assert.match(harness.board.innerHTML, /data-project-active-run-cancel-id="run-z"/);
  assert.match(harness.board.innerHTML, /data-project-run-slot-escalate="b-queued"/);
  assert.match(harness.board.innerHTML, /lease run alice\/z-active\/run-z/);
  assert.match(
    harness.board.innerHTML,
    /<article class="project-item" aria-selected="true">[\s\S]*data-project-concurrency-project="b-queued"/,
  );

  const activeRunButton = harness.board.querySelectorAll("[data-project-active-run-id]")[0];
  assert.ok(activeRunButton);
  activeRunButton.click();
  assert.deepEqual(harness.openedActiveRuns, [{ project: "z-active", runId: "run-z" }]);

  const activeRunPauseButton = harness.board.querySelectorAll("[data-project-active-run-pause-id]")[0];
  assert.ok(activeRunPauseButton);
  activeRunPauseButton.click();
  assert.deepEqual(harness.pausedActiveRuns, [{ project: "z-active", runId: "run-z" }]);

  const activeRunCancelButton = harness.board.querySelectorAll("[data-project-active-run-cancel-id]")[0];
  assert.ok(activeRunCancelButton);
  activeRunCancelButton.click();
  assert.deepEqual(harness.cancelledActiveRuns, [{ project: "z-active", runId: "run-z" }]);

  harness.escalationToolsInput.value = "shell.exec";
  const runSlotEscalationButton = harness.board.querySelectorAll("[data-project-run-slot-escalate]")[0];
  assert.ok(runSlotEscalationButton);
  runSlotEscalationButton.click();
  assert.equal(harness.escalationToolsInput.value, "");
  assert.equal(harness.escalationMaxActiveRunsInput.value, "2");
  assert.match(harness.escalationReasonInput.value, /b-queued/);
  assert.match(harness.escalationReasonInput.value, /tenant run cap 1/);
  assert.equal(harness.state.pendingEscalationSource.kind, "run_slot_pressure");
  assert.equal(harness.state.pendingEscalationSource.project, "b-queued");
  assert.equal(harness.state.pendingEscalationSource.runId, "run-b");
  assert.equal(harness.state.pendingEscalationSource.detail, "project #1 / tenant #1: tenant run cap 1");
  assert.equal(harness.connection.textContent, "run slot escalation prefilled");

  const activeButton = harness.board.querySelectorAll("[data-project-concurrency-project]").at(-1);
  assert.ok(activeButton);
  activeButton.click();
  assert.deepEqual(harness.selectedProjects, ["z-active"]);

  harness.state.projects = [{ project: "idle", runCount: 0 }];
  harness.renderProjects();
  assert.equal(harness.board.innerHTML, '<div class="empty">No project concurrency pressure.</div>');
});

test("dashboard project cards can stage agent-git-service provisioning plan for missing project agents", () => {
  const harness = createDashboardProjectConcurrencyHarness();
  harness.state.projects = [
    {
      project: "needs-ags",
      repo: "team/app",
      runCount: 0,
      controlPlane: {
        provider: "agent-git-service",
        agentGitServiceProjectAgent: {
          ready: false,
          receiptPresent: false,
          secretRootConfigured: true,
          secretStored: false,
        },
      },
    },
    {
      project: "ready-ags",
      repo: "team/ready",
      runCount: 0,
      controlPlane: {
        provider: "agent-git-service",
        agentGitServiceProjectAgent: {
          ready: true,
          receiptPresent: true,
          secretRootConfigured: true,
          secretStored: true,
        },
      },
    },
  ];

  harness.renderProjects();

  assert.match(harness.projectList.innerHTML, /data-project-agent-git-service-plan="needs-ags"/);
  assert.equal(harness.projectList.innerHTML.includes('data-project-agent-git-service-plan="ready-ags"'), false);
  const button = harness.projectList.querySelectorAll("[data-project-agent-git-service-plan]")[0];
  assert.ok(button);
  button.click();
  assert.equal(harness.agentGitServiceProvisioningPlanProjectsInput.value, "needs-ags");
  assert.equal(harness.agentGitServiceProvisioningPlanEligibleOnlyInput.checked, true);
  assert.equal(harness.connection.textContent, "AGS provisioning plan prefilled");
});

