test("HTTP harness tracks run workbench presence", async () => {
  const workspaceRoot = await tempDir("loom-http-presence");

  await withServer(workspaceRoot, async (baseUrl) => {
    const create = await fetch(`${baseUrl}/runs`, {
      method: "POST",
      headers: { "content-type": "application/json", authorization: "Bearer dev-key" },
      body: JSON.stringify({
        tenant: "alice",
        goal: "presence run",
        script: [{ message: "finish", finish: true }],
        verify: [],
        skills: ["coding"],
      }),
    });
    assert.equal(create.status, 201);
    const summary = await create.json();

    const first = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/presence`, {
      method: "POST",
      headers: { "content-type": "application/json", authorization: "Bearer viewer-key" },
      body: JSON.stringify({ clientId: "tab-1", label: "Alice", focus: "file:src/app.ts" }),
    });
    assert.equal(first.status, 200);
    const firstEntry = await first.json();
    assert.equal(firstEntry.clientId, "tab-1");
    assert.equal(firstEntry.label, "Alice");
    assert.equal(firstEntry.tenant, "alice");
    assert.equal(firstEntry.project, "default");
    assert.equal(firstEntry.runId, summary.runId);
    assert.equal(firstEntry.focus, "file:src/app.ts");
    assert.equal(firstEntry.actor, "auditor");
    assert.equal(firstEntry.role, "viewer");
    assert.ok(firstEntry.seenAt);
    assert.ok(firstEntry.expiresAt);

    const second = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/presence`, {
      method: "POST",
      headers: { "content-type": "application/json", authorization: "Bearer dev-key" },
      body: JSON.stringify({ clientId: "tab-2", label: "Bob", focus: "terminal:shell-1" }),
    });
    assert.equal(second.status, 200);
    const secondEntry = await second.json();
    assert.equal(secondEntry.actor, "eno");
    assert.equal(secondEntry.role, "developer");

    const update = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/presence`, {
      method: "POST",
      headers: { "content-type": "application/json", authorization: "Bearer viewer-key" },
      body: JSON.stringify({ clientId: "tab-1", label: "Alice Cooper", focus: "review-summary" }),
    });
    assert.equal(update.status, 200);

    const read = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/presence`, {
      headers: { authorization: "Bearer viewer-key" },
    });
    assert.equal(read.status, 200);
    const presence = await read.json();
    assert.equal(presence.length, 2);
    assert.deepEqual(
      presence.map((entry: any) => [entry.clientId, entry.label]).sort(),
      [["tab-1", "Alice Cooper"], ["tab-2", "Bob"]],
    );
    assert.deepEqual(
      presence.map((entry: any) => [entry.clientId, entry.focus]).sort(),
      [["tab-1", "review-summary"], ["tab-2", "terminal:shell-1"]],
    );
    assert.deepEqual(
      presence.map((entry: any) => [entry.clientId, entry.actor, entry.role]).sort(),
      [["tab-1", "auditor", "viewer"], ["tab-2", "eno", "developer"]],
    );
  }, {
    tenantApiKeys: {
      alice: [
        { token: "dev-key", actor: "eno", role: "developer" },
        { token: "viewer-key", actor: "auditor", role: "viewer" },
      ],
    },
  });
});

test("HTTP harness tracks tenant project dashboard presence", async () => {
  const workspaceRoot = await tempDir("loom-http-project-presence");

  await withServer(workspaceRoot, async (baseUrl) => {
    const createProject = await fetch(`${baseUrl}/tenants/alice/projects`, {
      method: "POST",
      headers: { "content-type": "application/json", authorization: "Bearer dev-key" },
      body: JSON.stringify({ project: "proj-a" }),
    });
    assert.equal(createProject.status, 201);

    const first = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/presence`, {
      method: "POST",
      headers: { "content-type": "application/json", authorization: "Bearer viewer-key" },
      body: JSON.stringify({ clientId: "dash-1", label: "Alice", focus: "project:proj-a" }),
    });
    assert.equal(first.status, 200);
    const firstEntry = await first.json();
    assert.equal(firstEntry.clientId, "dash-1");
    assert.equal(firstEntry.label, "Alice");
    assert.equal(firstEntry.tenant, "alice");
    assert.equal(firstEntry.project, "proj-a");
    assert.equal(firstEntry.focus, "project:proj-a");
    assert.equal(firstEntry.actor, "auditor");
    assert.equal(firstEntry.role, "viewer");
    assert.ok(firstEntry.seenAt);
    assert.ok(firstEntry.expiresAt);

    const second = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/presence`, {
      method: "POST",
      headers: { "content-type": "application/json", authorization: "Bearer dev-key" },
      body: JSON.stringify({ clientId: "dash-2", label: "Bob", focus: "run:run-1" }),
    });
    assert.equal(second.status, 200);

    const update = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/presence`, {
      method: "POST",
      headers: { "content-type": "application/json", authorization: "Bearer viewer-key" },
      body: JSON.stringify({ clientId: "dash-1", label: "Alice Cooper", focus: "file:README.md" }),
    });
    assert.equal(update.status, 200);

    const read = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/presence`, {
      headers: { authorization: "Bearer viewer-key" },
    });
    assert.equal(read.status, 200);
    const presence = await read.json();
    assert.equal(presence.length, 2);
    assert.deepEqual(
      presence.map((entry: any) => [entry.clientId, entry.label]).sort(),
      [["dash-1", "Alice Cooper"], ["dash-2", "Bob"]],
    );
    assert.deepEqual(
      presence.map((entry: any) => [entry.clientId, entry.focus]).sort(),
      [["dash-1", "file:README.md"], ["dash-2", "run:run-1"]],
    );
    assert.deepEqual(
      presence.map((entry: any) => [entry.clientId, entry.actor, entry.role]).sort(),
      [["dash-1", "auditor", "viewer"], ["dash-2", "eno", "developer"]],
    );

    const projects = await fetch(`${baseUrl}/tenants/alice/projects`, {
      headers: { authorization: "Bearer viewer-key" },
    });
    assert.equal(projects.status, 200);
    const projectList = await projects.json();
    const projectSummary = projectList.find((project: any) => project.project === "proj-a");
    assert.equal(projectSummary.activeProjectCollaboratorCount, 2);
    assert.deepEqual(
      projectSummary.activeProjectCollaborators.map((entry: any) => [entry.clientId, entry.label, entry.focus]).sort(),
      [["dash-1", "Alice Cooper", "file:README.md"], ["dash-2", "Bob", "run:run-1"]],
    );

    const projectDetail = await fetch(`${baseUrl}/tenants/alice/projects/proj-a`, {
      headers: { authorization: "Bearer viewer-key" },
    });
    assert.equal(projectDetail.status, 200);
    const projectDetailBody = await projectDetail.json();
    assert.equal(projectDetailBody.activeProjectCollaboratorCount, 2);
    assert.deepEqual(
      projectDetailBody.activeProjectCollaborators.map((entry: any) => [entry.clientId, entry.actor, entry.role]).sort(),
      [["dash-1", "auditor", "viewer"], ["dash-2", "eno", "developer"]],
    );
  }, {
    tenantApiKeys: {
      alice: [
        { token: "dev-key", actor: "eno", role: "developer" },
        { token: "viewer-key", actor: "auditor", role: "viewer" },
      ],
    },
  });
});

test("HTTP harness shares tenant project dashboard presence across server instances", async () => {
  const workspaceRoot = await tempDir("loom-http-cross-server-project-presence");
  await writeProjectRegistration(workspaceRoot, "alice", "proj-a");
  const options = {
    tenantApiKeys: {
      alice: [
        { token: "dev-key", actor: "eno", role: "developer" },
        { token: "viewer-key", actor: "auditor", role: "viewer" },
      ],
    },
  };

  await withServer(
    workspaceRoot,
    async (firstBaseUrl) => {
      await withServer(
        workspaceRoot,
        async (secondBaseUrl) => {
          const first = await fetch(`${firstBaseUrl}/tenants/alice/projects/proj-a/presence`, {
            method: "POST",
            headers: { "content-type": "application/json", authorization: "Bearer viewer-key" },
            body: JSON.stringify({ clientId: "dash-1", label: "Alice", focus: "file:README.md" }),
          });
          assert.equal(first.status, 200);

          const second = await fetch(`${secondBaseUrl}/tenants/alice/projects/proj-a/presence`, {
            method: "POST",
            headers: { "content-type": "application/json", authorization: "Bearer dev-key" },
            body: JSON.stringify({ clientId: "dash-2", label: "Bob", focus: "run:run-1" }),
          });
          assert.equal(second.status, 200);

          const read = await fetch(`${secondBaseUrl}/tenants/alice/projects/proj-a/presence`, {
            headers: { authorization: "Bearer viewer-key" },
          });
          assert.equal(read.status, 200);
          const presence = await read.json();
          assert.deepEqual(
            presence.map((entry: any) => [entry.clientId, entry.label, entry.focus, entry.actor, entry.role]).sort(),
            [
              ["dash-1", "Alice", "file:README.md", "auditor", "viewer"],
              ["dash-2", "Bob", "run:run-1", "eno", "developer"],
            ],
          );

          const projects = await fetch(`${secondBaseUrl}/tenants/alice/projects`, {
            headers: { authorization: "Bearer viewer-key" },
          });
          assert.equal(projects.status, 200);
          const projectSummary = (await projects.json()).find((project: any) => project.project === "proj-a");
          assert.equal(projectSummary.activeProjectCollaboratorCount, 2);
          assert.deepEqual(
            projectSummary.activeProjectCollaborators.map((entry: any) => [entry.clientId, entry.label, entry.focus]).sort(),
            [["dash-1", "Alice", "file:README.md"], ["dash-2", "Bob", "run:run-1"]],
          );
        },
        options,
      );
    },
    options,
  );
});

