test("HTTP harness creates projects with golden path defaults in one request", async () => {
  const workspaceRoot = await tempDir("loom-http-project-create-golden-path");

  await withServer(
    workspaceRoot,
    async (baseUrl) => {
      const contract = {
        objective: HARNESS_VISION_LOCK.target,
        constraints: [
          "Keep multi-user online sandbox collaboration visible in project evidence.",
          "Keep harness/loop evidence durable in .loom project state.",
          "Keep human review and deployment gates explicit.",
          "Keep VAS learning artifacts reviewable and durable.",
        ],
        successCriteria: [
          "Runs inherit the project review preset without manual re-entry.",
          "Run metadata carries project policy and contract evidence.",
        ],
      };
      const runPolicy = {
        preset: "vas-lite-review",
        presetInput: { caseId: "bootstrap" },
        reviewRequired: true,
      };
      const create = await fetch(`${baseUrl}/tenants/alice/projects`, {
        method: "POST",
        headers: { "content-type": "application/json", authorization: "Bearer dev-key" },
        body: JSON.stringify({
          project: "lesson-vas",
          template: "vas-lite",
          defaultSkills: ["vas-lite", "coding", "review"],
          ...runPolicy,
          ...contract,
          clientId: "dash-golden-path",
        }),
      });
      assert.equal(create.status, 201);
      const createdProject = await create.json();
      assert.deepEqual(createdProject.defaultSkills, ["vas-lite", "coding", "review"]);
      assert.deepEqual(createdProject.runPolicy, runPolicy);
      assert.deepEqual(createdProject.contract, contract);
      assert.deepEqual(createdProject.contractStatus, { ok: true, missing: [] });
      assert.equal(createdProject.latestControlActivity.type, "project_created");
      assert.equal(createdProject.latestControlActivity.template, "vas-lite");
      assert.deepEqual(createdProject.latestControlActivity.defaultSkills, ["vas-lite", "coding", "review"]);
      assert.deepEqual(createdProject.latestControlActivity.runPolicy, runPolicy);
      assert.deepEqual(createdProject.latestControlActivity.contract, contract);
      assert.equal(createdProject.latestControlActivity.actor, "dev-user");
      assert.equal(createdProject.latestControlActivity.clientId, "dash-golden-path");

      const metadata = JSON.parse(await readFile(join(workspaceRoot, "alice", "lesson-vas", ".loom", "project.json"), "utf8"));
      assert.deepEqual(metadata.defaultSkills, ["vas-lite", "coding", "review"]);
      assert.deepEqual(metadata.runPolicy, runPolicy);
      assert.deepEqual(metadata.contract, contract);

      const inherited = await fetch(`${baseUrl}/runs`, {
        method: "POST",
        headers: { "content-type": "application/json", authorization: "Bearer dev-key" },
        body: JSON.stringify({ tenant: "alice", project: "lesson-vas" }),
      });
      assert.equal(inherited.status, 201);
      const summary = await inherited.json();
      assert.equal(summary.status, "review_required");
      assert.deepEqual(summary.skills, ["vas-lite", "coding", "review"]);
      assert.equal(summary.metadata.runPreset, "vas-lite-review");
      assert.deepEqual(summary.metadata.projectRunPolicy, {
        source: "project.runPolicy",
        fields: ["preset", "presetInput", "reviewRequired"],
        ...runPolicy,
      });
      assert.deepEqual(summary.metadata.projectContract, { source: "project.contract", ...contract });

      const audit = await fetch(`${baseUrl}/tenants/alice/audit?project=lesson-vas`, {
        headers: { authorization: "Bearer viewer-key" },
      });
      assert.equal(audit.status, 200);
      const events = await audit.json();
      assert.ok(events.some((event: any) =>
        event.type === "project_created" &&
        event.data.project === "lesson-vas" &&
        event.data.clientId === "dash-golden-path" &&
        JSON.stringify(event.data.defaultSkills) === JSON.stringify(["vas-lite", "coding", "review"]) &&
        JSON.stringify(event.data.runPolicy) === JSON.stringify(runPolicy) &&
        JSON.stringify(event.data.contract) === JSON.stringify(contract)
      ));
    },
    {
      tenantApiKeys: {
        alice: [
          { token: "dev-key", actor: "dev-user", role: "developer" },
          { token: "viewer-key", actor: "view-user", role: "viewer" },
        ],
      },
    },
  );
});

test("HTTP harness reads tenant project registry details", async () => {
  const workspaceRoot = await tempDir("loom-http-project-detail");

  await withServer(
    workspaceRoot,
    async (baseUrl) => {
      const create = await fetch(`${baseUrl}/tenants/alice/projects`, {
        method: "POST",
        headers: { "content-type": "application/json", authorization: "Bearer dev-key" },
        body: JSON.stringify({
          project: "proj-a",
          repo: "team/proj-a",
          branch: "feature/detail",
          baseBranch: "main",
          issue: "team/proj-a#9",
        }),
      });
      assert.equal(create.status, 201);

      const run = await fetch(`${baseUrl}/runs`, {
        method: "POST",
        headers: { "content-type": "application/json", authorization: "Bearer dev-key" },
        body: JSON.stringify({
          tenant: "alice",
          project: "proj-a",
          goal: "record project activity",
          script: [{ message: "finish", finish: true }],
          verify: [],
          skills: ["coding"],
        }),
      });
      assert.equal(run.status, 201);
      const summary = await run.json();

      const detail = await fetch(`${baseUrl}/tenants/alice/projects/proj-a`, {
        headers: { authorization: "Bearer viewer-key" },
      });
      const detailText = await detail.text();
      assert.equal(detail.status, 200, detailText);
      const body = JSON.parse(detailText);
      assert.equal(body.project, "proj-a");
      assert.equal(body.template, "empty");
      assert.match(body.createdAt, /^\d{4}-\d{2}-\d{2}T/);
      assert.equal(body.repo, "team/proj-a");
      assert.equal(body.branch, "feature/detail");
      assert.equal(body.baseBranch, "main");
      assert.equal(body.issue, "team/proj-a#9");
      assert.equal(body.runCount, 1);
      assert.equal(body.latestRunId, summary.runId);
      assert.equal(body.latestStatus, "passed");
      assert.match(body.latestStartedAt, /^\d{4}-\d{2}-\d{2}T/);
      assert.equal(body.activityAt, body.latestStartedAt);

      await new Promise((resolve) => setTimeout(resolve, 10));
      const command = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/commands`, {
        method: "POST",
        headers: { "content-type": "application/json", authorization: "Bearer dev-key" },
        body: JSON.stringify({ command: "printf detail-activity > activity.txt" }),
      });
      const commandText = await command.text();
      assert.equal(command.status, 200, commandText);
      const commandBody = JSON.parse(commandText);
      assert.match(commandBody.endedAt, /^\d{4}-\d{2}-\d{2}T/);
      assert.notEqual(commandBody.endedAt, body.latestStartedAt);

      const commandDetail = await fetch(`${baseUrl}/tenants/alice/projects/proj-a`, {
        headers: { authorization: "Bearer viewer-key" },
      });
      const commandDetailText = await commandDetail.text();
      assert.equal(commandDetail.status, 200, commandDetailText);
      const commandDetailBody = JSON.parse(commandDetailText);
      assert.equal(commandDetailBody.latestRunId, summary.runId);
      assert.equal(commandDetailBody.activityAt, commandBody.endedAt);

      const commandList = await fetch(`${baseUrl}/tenants/alice/projects`, {
        headers: { authorization: "Bearer viewer-key" },
      });
      const commandListText = await commandList.text();
      assert.equal(commandList.status, 200, commandListText);
      const commandListBody = JSON.parse(commandListText);
      assert.equal(commandListBody[0].project, "proj-a");
      assert.equal(commandListBody[0].activityAt, commandBody.endedAt);

      const missing = await fetch(`${baseUrl}/tenants/alice/projects/plain`, {
        headers: { authorization: "Bearer viewer-key" },
      });
      assert.equal(missing.status, 404);
      assert.match((await missing.json()).error, /project not found/);
    },
    {
      tenantApiKeys: {
        alice: [
          { token: "dev-key", actor: "dev-user", role: "developer" },
          { token: "viewer-key", actor: "view-user", role: "viewer" },
        ],
      },
      allowedTools: ["file.read", "file.write", "shell.exec", "git.diff", "verify.run"],
    },
  );
});

