      assert.equal(updatedProject.issue, "team/proj-a#77");
      assert.equal(updatedProject.latestControlActivity.type, "project_source_defaults_updated");
      assert.equal(updatedProject.latestControlActivity.repo, "team/proj-a");
      assert.equal(updatedProject.latestControlActivity.branch, "feature/updated-default");
      assert.equal(updatedProject.latestControlActivity.baseBranch, "main");
