      const lessonWithUnreviewedRun = (await projectsWithUnreviewedRun.json()).find((item: any) => item.project === "lesson-vas");
      assert.equal(lessonWithUnreviewedRun.runCount, 1);
      assert.equal(lessonWithUnreviewedRun.vasCaseCount, 1);
