      const caseSummary = await createCaseRun.json();
      assert.equal(caseSummary.status, "passed");
      assert.equal(caseSummary.goal, "Review VAS Lite case segment-001");
      assert.equal(caseSummary.metadata.runPresetInput.caseId, "segment-001");
      assert.equal(caseSummary.metadata.runPresetInput.priorLearningCount, 1);
