test("HTTP harness saves tenant project workspace files safely", async () => {
  const workspaceRoot = await tempDir("loom-http-workspace-file-save");
  const projectRoot = join(workspaceRoot, "alice", "proj-a");
  await writeProjectRegistration(workspaceRoot, "alice", "proj-a");
  await mkdir(join(projectRoot, "src"), { recursive: true });
  await writeFile(join(projectRoot, "src", "index.ts"), "old\n", "utf8");

  await withServer(workspaceRoot, async (baseUrl) => {
    const save = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/files`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ path: "src/index.ts", content: "export const ok = true;\n" }),
    });
    assert.equal(save.status, 200);
    const saved = await save.json();
    assert.equal(saved.kind, "file");
    assert.equal(saved.path, "src/index.ts");
    assert.equal(saved.content, "export const ok = true;\n");
    assert.equal(await readFile(join(projectRoot, "src", "index.ts"), "utf8"), "export const ok = true;\n");

    const createNested = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/files`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ path: "notes/today.md", content: "# Notes\n" }),
    });
    assert.equal(createNested.status, 200);
    const nested = await createNested.json();
    assert.equal(await readFile(join(projectRoot, "notes", "today.md"), "utf8"), "# Notes\n");

    const moveNested = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/files/move`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ fromPath: "notes/today.md", toPath: "notes/archive/today.md", baseUpdatedAt: nested.updatedAt, clientId: "dash-move" }),
    });
    assert.equal(moveNested.status, 200);
    const moved = await moveNested.json();
    assert.equal(moved.path, "notes/archive/today.md");
    assert.equal(moved.previousPath, "notes/today.md");
    assert.equal(moved.content, "# Notes\n");
    assert.equal(await readFile(join(projectRoot, "notes", "archive", "today.md"), "utf8"), "# Notes\n");
    await assert.rejects(readFile(join(projectRoot, "notes", "today.md"), "utf8"), { code: "ENOENT" });

    const moveOverExisting = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/files/move`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ fromPath: "notes/archive/today.md", toPath: "src/index.ts", baseUpdatedAt: moved.updatedAt, clientId: "dash-move" }),
    });
    assert.equal(moveOverExisting.status, 400);
    assert.match((await moveOverExisting.json()).error, /already exists/);

    const deleteNested = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/files?path=notes/archive/today.md`, {
      method: "DELETE",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ clientId: "dash-delete" }),
    });
    assert.equal(deleteNested.status, 200);
    assert.deepEqual(await deleteNested.json(), { path: "notes/archive/today.md", kind: "deleted" });
    await assert.rejects(readFile(join(projectRoot, "notes", "archive", "today.md"), "utf8"), { code: "ENOENT" });

    const deleteDirectory = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/files?path=src`, {
      method: "DELETE",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ clientId: "dash-delete" }),
    });
    assert.equal(deleteDirectory.status, 400);
    assert.match((await deleteDirectory.json()).error, /must be a file/);

    const dotLoom = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/files`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ path: ".loom/status.json", content: "{}" }),
    });
    assert.equal(dotLoom.status, 400);
    assert.match((await dotLoom.json()).error, /internal workspace path/);

    const escape = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/files`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ path: "../proj-b/out.txt", content: "bad" }),
    });
    assert.equal(escape.status, 400);
    assert.match((await escape.json()).error, /stay inside workspace/);
  });
});

test("HTTP harness enforces tenant workspace byte limits for workspace file writes", async () => {
  const workspaceRoot = await tempDir("loom-http-workspace-byte-file-limit");
  const projectRoot = join(workspaceRoot, "alice", "proj-a");
  await mkdir(join(workspaceRoot, "alice", ".loom"), { recursive: true });
  await writeFile(
    join(workspaceRoot, "alice", ".loom", "policy.json"),
    JSON.stringify({ schemaVersion: 1, limits: { maxWorkspaceBytes: 8 } }),
    "utf8",
  );
  await writeProjectRegistration(workspaceRoot, "alice", "proj-a");
  await mkdir(join(projectRoot, ".loom"), { recursive: true });
  await writeFile(join(projectRoot, "seed.txt"), "12345", "utf8");
  await writeFile(join(projectRoot, ".loom", "ignored.txt"), "this control data is not counted", "utf8");

  await withServer(workspaceRoot, async (baseUrl) => {
    const info = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/workspace`);
    assert.equal(info.status, 200);
    const workspace = await info.json();
    assert.equal(workspace.workspaceBytes, 5);
    assert.equal(workspace.workspaceByteLimit, 8);

    const allowed = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/files`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ path: "notes.txt", content: "abc" }),
    });
    assert.equal(allowed.status, 200);

    const rejected = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/files`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ path: "overflow.txt", content: "x" }),
    });
    assert.equal(rejected.status, 409);
    assert.match((await rejected.json()).error, /workspace byte limit exceeded: 9 > 8/);
    await assert.rejects(readFile(join(projectRoot, "overflow.txt"), "utf8"), { code: "ENOENT" });

    const shrink = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/files`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ path: "seed.txt", content: "z" }),
    });
    assert.equal(shrink.status, 200);
    assert.equal(await readFile(join(projectRoot, "seed.txt"), "utf8"), "z");
  });
});

test("HTTP harness includes active project file editors in stale workspace file conflicts", async () => {
  const workspaceRoot = await tempDir("loom-http-project-workspace-file-conflict");
  await writeProjectRegistration(workspaceRoot, "alice", "proj-a");
  const files = new Map<string, string>([
    ["src/index.ts", "export const projectScoped = true;\n"],
  ]);
  let updatedAt = "2026-06-26T00:00:00.000Z";

  await withServer(
    workspaceRoot,
    async (baseUrl) => {
      const read = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/files?path=src/index.ts`, {
        headers: { authorization: "Bearer dev-key" },
      });
      assert.equal(read.status, 200);
      const loaded = await read.json();
      assert.equal(loaded.updatedAt, "2026-06-26T00:00:00.000Z");

      const peerPresence = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/presence`, {
        method: "POST",
        headers: { "content-type": "application/json", authorization: "Bearer viewer-key" },
        body: JSON.stringify({ clientId: "peer-tab", label: "Peer", focus: "file:src/index.ts" }),
      });
      assert.equal(peerPresence.status, 200);

      const writerPresence = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/presence`, {
        method: "POST",
        headers: { "content-type": "application/json", authorization: "Bearer dev-key" },
        body: JSON.stringify({ clientId: "writer-tab", label: "Writer", focus: "file:src/index.ts" }),
      });
      assert.equal(writerPresence.status, 200);

      const otherFilePresence = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/presence`, {
        method: "POST",
        headers: { "content-type": "application/json", authorization: "Bearer viewer-key" },
        body: JSON.stringify({ clientId: "other-tab", label: "Other", focus: "file:README.md" }),
      });
      assert.equal(otherFilePresence.status, 200);

      files.set("src/index.ts", "export const external = true;\n");
      updatedAt = "2026-06-26T00:00:01.000Z";

      const staleSave = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/files`, {
        method: "POST",
        headers: { "content-type": "application/json", authorization: "Bearer dev-key" },
        body: JSON.stringify({
          path: "src/index.ts",
          content: "export const overwritten = true;\n",
          baseUpdatedAt: loaded.updatedAt,
          clientId: "writer-tab",
        }),
      });
      assert.equal(staleSave.status, 409);
      const conflictBody = await staleSave.json();
      assert.match(conflictBody.error, /changed since it was loaded/);
      assert.deepEqual(
        conflictBody.activeEditors.map((entry: any) => ({
          tenant: entry.tenant,
          project: entry.project,
          runId: entry.runId,
          clientId: entry.clientId,
          label: entry.label,
          focus: entry.focus,
          actor: entry.actor,
          role: entry.role,
        })),
        [
          {
            tenant: "alice",
            project: "proj-a",
            runId: undefined,
            clientId: "peer-tab",
            label: "Peer",
            focus: "file:src/index.ts",
            actor: "view-user",
            role: "viewer",
          },
        ],
      );
      assert.equal(files.get("src/index.ts"), "export const external = true;\n");

      const staleDelete = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/files?path=src/index.ts`, {
        method: "DELETE",
        headers: { "content-type": "application/json", authorization: "Bearer dev-key" },
        body: JSON.stringify({
          baseUpdatedAt: loaded.updatedAt,
          clientId: "writer-tab",
        }),
      });
      assert.equal(staleDelete.status, 409);
      const deleteConflictBody = await staleDelete.json();
      assert.match(deleteConflictBody.error, /changed since it was loaded/);
      assert.deepEqual(
        deleteConflictBody.activeEditors.map((entry: any) => ({
          tenant: entry.tenant,
          project: entry.project,
          runId: entry.runId,
          clientId: entry.clientId,
          label: entry.label,
          focus: entry.focus,
          actor: entry.actor,
          role: entry.role,
        })),
        [
          {
            tenant: "alice",
            project: "proj-a",
            runId: undefined,
            clientId: "peer-tab",
            label: "Peer",
            focus: "file:src/index.ts",
            actor: "view-user",
            role: "viewer",
          },
        ],
      );
      assert.equal(files.get("src/index.ts"), "export const external = true;\n");

      const audit = await fetch(`${baseUrl}/tenants/alice/audit?project=proj-a`, {
        headers: { authorization: "Bearer dev-key" },
      });
      assert.equal(audit.status, 200);
      const auditEvents = await audit.json();
      const conflicts = auditEvents.filter((event: any) => event.type === "workspace_file_conflicted");
      assert.deepEqual(
        conflicts.map((event: any) => ({
          actor: event.actor,
          role: event.role,
          project: event.data.project,
          runId: event.data.runId,
          operation: event.data.operation,
          path: event.data.path,
          clientId: event.data.clientId,
          expectedUpdatedAt: event.data.expectedUpdatedAt,
          observedUpdatedAt: event.data.observedUpdatedAt,
          observedKind: event.data.observedKind,
          activeEditorCount: event.data.activeEditorCount,
          activeEditors: event.data.activeEditors.map((entry: any) => [entry.clientId, entry.label, entry.focus]),
        })),
        [
          {
            actor: "dev-user",
            role: "developer",
            project: "proj-a",
            runId: undefined,
            operation: "write",
            path: "src/index.ts",
            clientId: "writer-tab",
            expectedUpdatedAt: "2026-06-26T00:00:00.000Z",
            observedUpdatedAt: "2026-06-26T00:00:01.000Z",
            observedKind: "file",
            activeEditorCount: 1,
            activeEditors: [["peer-tab", "Peer", "file:src/index.ts"]],
          },
          {
            actor: "dev-user",
            role: "developer",
            project: "proj-a",
            runId: undefined,
            operation: "delete",
            path: "src/index.ts",
            clientId: "writer-tab",
            expectedUpdatedAt: "2026-06-26T00:00:00.000Z",
            observedUpdatedAt: "2026-06-26T00:00:01.000Z",
            observedKind: "file",
            activeEditorCount: 1,
            activeEditors: [["peer-tab", "Peer", "file:src/index.ts"]],
          },
        ],
      );

      const brainFeed = await fetch(`${baseUrl}/tenants/alice/brain/signals?project=proj-a`, {
        headers: { authorization: "Bearer viewer-key" },
      });
      assert.equal(brainFeed.status, 200);
      const brainBody = await brainFeed.json();
      const conflictSignals = brainBody.signals.filter((signal: any) => signal.source === "workspace_conflict");
      assert.deepEqual(
        conflictSignals.map((signal: any) => ({
          actor: signal.actor,
          role: signal.role,
          project: signal.project,
          runId: signal.runId,
          operation: signal.operation,
          path: signal.path,
          clientId: signal.clientId,
          expectedUpdatedAt: signal.expectedUpdatedAt,
          observedUpdatedAt: signal.observedUpdatedAt,
          observedKind: signal.observedKind,
          activeEditorCount: signal.activeEditorCount,
        })),
        [
          {
            actor: "dev-user",
            role: "developer",
            project: "proj-a",
            runId: undefined,
            operation: "write",
            path: "src/index.ts",
            clientId: "writer-tab",
            expectedUpdatedAt: "2026-06-26T00:00:00.000Z",
            observedUpdatedAt: "2026-06-26T00:00:01.000Z",
            observedKind: "file",
            activeEditorCount: 1,
          },
          {
            actor: "dev-user",
            role: "developer",
            project: "proj-a",
            runId: undefined,
            operation: "delete",
            path: "src/index.ts",
            clientId: "writer-tab",
            expectedUpdatedAt: "2026-06-26T00:00:00.000Z",
            observedUpdatedAt: "2026-06-26T00:00:01.000Z",
            observedKind: "file",
            activeEditorCount: 1,
          },
        ],
      );

      const projects = await fetch(`${baseUrl}/tenants/alice/projects`, {
        headers: { authorization: "Bearer viewer-key" },
      });
      assert.equal(projects.status, 200);
      const projectSummaries = await projects.json();
      const projectSummary = projectSummaries.find((project: any) => project.project === "proj-a");
      assert.equal(projectSummary.workspaceConflictCount, 2);
      assert.deepEqual(
        {
          type: projectSummary.latestWorkspaceConflict.type,
          actor: projectSummary.latestWorkspaceConflict.actor,
          role: projectSummary.latestWorkspaceConflict.role,
          operation: projectSummary.latestWorkspaceConflict.operation,
          path: projectSummary.latestWorkspaceConflict.path,
          clientId: projectSummary.latestWorkspaceConflict.clientId,
          expectedUpdatedAt: projectSummary.latestWorkspaceConflict.expectedUpdatedAt,
          observedUpdatedAt: projectSummary.latestWorkspaceConflict.observedUpdatedAt,
          observedKind: projectSummary.latestWorkspaceConflict.observedKind,
          activeEditorCount: projectSummary.latestWorkspaceConflict.activeEditorCount,
        },
        {
          type: "workspace_file_conflicted",
          actor: "dev-user",
          role: "developer",
          operation: "delete",
          path: "src/index.ts",
          clientId: "writer-tab",
          expectedUpdatedAt: "2026-06-26T00:00:00.000Z",
          observedUpdatedAt: "2026-06-26T00:00:01.000Z",
          observedKind: "file",
          activeEditorCount: 1,
        },
      );
      assert.ok(projectSummary.concurrency);
      assert.equal(projectSummary.concurrency.state, "contended");
      assert.equal(projectSummary.concurrency.workspaceConflictCount, 2);
      assert.equal(projectSummary.concurrency.activeProjectCollaboratorCount, 3);
      assert.equal(projectSummary.concurrency.latestWorkspaceConflict.operation, "delete");
      assert.equal(projectSummary.concurrency.latestWorkspaceConflict.path, "src/index.ts");

      const projectDetailResponse = await fetch(`${baseUrl}/tenants/alice/projects/proj-a`, {
        headers: { authorization: "Bearer viewer-key" },
      });
      assert.equal(projectDetailResponse.status, 200);
      const projectDetail = await projectDetailResponse.json();
      assert.equal(projectDetail.workspaceConflictCount, 2);
      assert.equal(projectDetail.latestWorkspaceConflict.operation, "delete");
      assert.equal(projectDetail.latestWorkspaceConflict.path, "src/index.ts");
      assert.ok(projectDetail.concurrency);
      assert.equal(projectDetail.concurrency.state, "contended");
      assert.equal(projectDetail.concurrency.workspaceConflictCount, 2);
      assert.equal(projectDetail.concurrency.activeProjectCollaboratorCount, 3);
    },
    {
      tenantApiKeys: {
        alice: [
          { token: "dev-key", actor: "dev-user", role: "developer" },
          { token: "viewer-key", actor: "view-user", role: "viewer" },
        ],
      },
      createExecutor: () => ({
        async prepare(): Promise<void> {},
        async inspectPath(path: string): Promise<any> {
          if (path === "src/index.ts") {
            return {
              path,
              kind: "file",
              size: files.get(path)?.length ?? 0,
              updatedAt,
            };
          }
          return { path, kind: "missing" };
        },
        async readFile(path: string): Promise<string> {
          return files.get(path) ?? "";
        },
        async writeFile(path: string, content: string): Promise<void> {
          files.set(path, content);
          updatedAt = "2026-06-26T00:00:02.000Z";
        },
        async runCommand(): Promise<{ stdout: string; stderr: string; exitCode: number }> {
          return { stdout: "", stderr: "", exitCode: 0 };
        },
      }),
    },
  );
});

test("HTTP harness includes cross-server active project file editors in stale workspace file conflicts", async () => {
  const workspaceRoot = await tempDir("loom-http-cross-server-project-workspace-file-conflict");
  await writeProjectRegistration(workspaceRoot, "alice", "proj-a");
  const files = new Map<string, string>([
    ["src/index.ts", "export const projectScoped = true;\n"],
  ]);
  let updatedAt = "2026-06-26T00:00:00.000Z";
  const options = {
    tenantApiKeys: {
      alice: [
        { token: "dev-key", actor: "dev-user", role: "developer" },
        { token: "viewer-key", actor: "view-user", role: "viewer" },
      ],
    },
    createExecutor: () => ({
      async prepare(): Promise<void> {},
      async inspectPath(path: string): Promise<any> {
        if (path === "src/index.ts") {
          return {
            path,
            kind: "file",
            size: files.get(path)?.length ?? 0,
            updatedAt,
          };
        }
        return { path, kind: "missing" };
      },
      async readFile(path: string): Promise<string> {
        return files.get(path) ?? "";
      },
      async writeFile(path: string, content: string): Promise<void> {
        files.set(path, content);
        updatedAt = "2026-06-26T00:00:02.000Z";
      },
      async runCommand(): Promise<{ stdout: string; stderr: string; exitCode: number }> {
        return { stdout: "", stderr: "", exitCode: 0 };
      },
    }),
  };

  await withServer(
    workspaceRoot,
    async (firstBaseUrl) => {
      await withServer(
        workspaceRoot,
        async (secondBaseUrl) => {
          const read = await fetch(`${secondBaseUrl}/tenants/alice/projects/proj-a/files?path=src/index.ts`, {
            headers: { authorization: "Bearer dev-key" },
          });
          assert.equal(read.status, 200);
          const loaded = await read.json();
          assert.equal(loaded.updatedAt, "2026-06-26T00:00:00.000Z");

          const peerPresence = await fetch(`${firstBaseUrl}/tenants/alice/projects/proj-a/presence`, {
            method: "POST",
            headers: { "content-type": "application/json", authorization: "Bearer viewer-key" },
            body: JSON.stringify({ clientId: "peer-tab", label: "Peer", focus: "file:src/index.ts" }),
          });
          assert.equal(peerPresence.status, 200);

          const writerPresence = await fetch(`${secondBaseUrl}/tenants/alice/projects/proj-a/presence`, {
            method: "POST",
            headers: { "content-type": "application/json", authorization: "Bearer dev-key" },
            body: JSON.stringify({ clientId: "writer-tab", label: "Writer", focus: "file:src/index.ts" }),
          });
          assert.equal(writerPresence.status, 200);

          files.set("src/index.ts", "export const external = true;\n");
          updatedAt = "2026-06-26T00:00:01.000Z";

          const staleSave = await fetch(`${secondBaseUrl}/tenants/alice/projects/proj-a/files`, {
            method: "POST",
            headers: { "content-type": "application/json", authorization: "Bearer dev-key" },
            body: JSON.stringify({
              path: "src/index.ts",
              content: "export const overwritten = true;\n",
              baseUpdatedAt: loaded.updatedAt,
              clientId: "writer-tab",
            }),
          });
          assert.equal(staleSave.status, 409);
          const conflictBody = await staleSave.json();
          assert.deepEqual(
            conflictBody.activeEditors.map((entry: any) => ({
              tenant: entry.tenant,
              project: entry.project,
              runId: entry.runId,
              clientId: entry.clientId,
              label: entry.label,
              focus: entry.focus,
              actor: entry.actor,
              role: entry.role,
            })),
            [
              {
                tenant: "alice",
                project: "proj-a",
                runId: undefined,
                clientId: "peer-tab",
                label: "Peer",
                focus: "file:src/index.ts",
                actor: "view-user",
                role: "viewer",
              },
            ],
          );
          assert.equal(files.get("src/index.ts"), "export const external = true;\n");
        },
        options,
      );
    },
    options,
  );
});

