test("HTTP harness browses and saves workspace files through the configured executor", async () => {
  const workspaceRoot = await tempDir("loom-http-workspace-file-executor");
  await writeProjectRegistration(workspaceRoot, "alice", "proj-a");
  const calls: string[] = [];
  const files = new Map<string, string>([
    ["README.md", "# Remote\n"],
    ["src/index.ts", "export const remote = true;\n"],
  ]);

  await withServer(
    workspaceRoot,
    async (baseUrl) => {
      const root = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/files`);
      assert.equal(root.status, 200);
      const rootBody = await root.json();
      assert.deepEqual(
        rootBody.entries.map((entry) => ({ name: entry.name, kind: entry.kind, path: entry.path })),
        [
          { name: "README.md", kind: "file", path: "README.md" },
          { name: "src", kind: "directory", path: "src" },
        ],
      );

      const file = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/files?path=src/index.ts`);
      assert.equal(file.status, 200);
      const fileBody = await file.json();
      assert.equal(fileBody.content, "export const remote = true;\n");

      const save = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/files`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ path: "src/index.ts", content: "export const saved = true;\n" }),
      });
      assert.equal(save.status, 200);
      assert.equal(files.get("src/index.ts"), "export const saved = true;\n");
    },
    {
      createExecutor: (_cwd: string, context: { tenant: string; project: string; runId?: string }) => {
        calls.push(`factory:${context.tenant}:${context.project}:${context.runId}`);
        return {
          async prepare(): Promise<void> {
            calls.push("prepare");
          },
          async inspectPath(path: string): Promise<any> {
            calls.push(`inspect:${path}`);
            if (path === "") {
              return {
                path,
                kind: "directory",
                entries: [
                  { name: "README.md", path: "README.md", kind: "file", size: files.get("README.md")?.length, updatedAt: "2026-06-26T00:00:00.000Z" },
                  { name: "src", path: "src", kind: "directory", updatedAt: "2026-06-26T00:00:00.000Z" },
                ],
              };
            }
            if (path === "src/index.ts") {
              return {
                path,
                kind: "file",
                size: files.get(path)?.length ?? 0,
                updatedAt: "2026-06-26T00:00:00.000Z",
              };
            }
            return { path, kind: "missing" };
          },
          async readFile(path: string): Promise<string> {
            calls.push(`read:${path}`);
            return files.get(path) ?? "";
          },
          async writeFile(path: string, content: string): Promise<void> {
            calls.push(`write:${path}:${content}`);
            files.set(path, content);
          },
          async runCommand(command: string): Promise<{ stdout: string; stderr: string; exitCode: number }> {
            calls.push(`run:${command}`);
            return { stdout: "", stderr: "", exitCode: 0 };
          },
        };
      },
    },
  );

  assert.deepEqual(calls, [
    "factory:alice:proj-a:workspace-files",
    "prepare",
    "inspect:",
    "factory:alice:proj-a:workspace-files",
    "prepare",
    "inspect:src/index.ts",
    "read:src/index.ts",
    "factory:alice:proj-a:workspace-files",
    "prepare",
    "inspect:src/index.ts",
    "write:src/index.ts:export const saved = true;\n",
    "inspect:src/index.ts",
    "read:src/index.ts",
  ]);
});

test("HTTP harness browses and saves run workspace files through the run executor context", async () => {
  const workspaceRoot = await tempDir("loom-http-run-workspace-file-executor");
  const calls: string[] = [];
  const files = new Map<string, string>([
    ["README.md", "# Run workspace\n"],
    ["src/index.ts", "export const runScoped = true;\n"],
  ]);

  await withServer(
    workspaceRoot,
    async (baseUrl) => {
      const project = await fetch(`${baseUrl}/tenants/alice/projects`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({
          project: "proj-a",
          repo: "https://git.example/team/proj-a.git",
          branch: "project/default-branch",
          baseBranch: "origin/project-main",
          issue: "team/proj-a#46",
        }),
      });
      assert.equal(project.status, 201);

      const created = await fetch(`${baseUrl}/runs`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({
          tenant: "alice",
          project: "proj-a",
          repo: "https://git.example/team/proj-a.git",
          branch: "task/run-files",
          baseBranch: "origin/main",
          goal: "create run-scoped workspace",
          script: [{ message: "finish", finish: true }],
          verify: [],
          skills: ["coding"],
        }),
      });
      assert.equal(created.status, 201);
      const summary = await created.json();
      assert.equal(summary.status, "passed");
      calls.length = 0;

      const root = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/files?project=proj-a`);
      assert.equal(root.status, 200);
      const rootBody = await root.json();
      assert.deepEqual(rootBody.entries.map((entry) => entry.path), ["README.md", "src"]);

      const file = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/files?project=proj-a&path=src/index.ts`);
      assert.equal(file.status, 200);
      assert.equal((await file.json()).content, "export const runScoped = true;\n");

      const save = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/files?project=proj-a`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ path: "src/index.ts", content: "export const savedForRun = true;\n" }),
      });
      assert.equal(save.status, 200);
      assert.equal(files.get("src/index.ts"), "export const savedForRun = true;\n");

      const saved = await save.json();
      const moved = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/files/move?project=proj-a`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ fromPath: "src/index.ts", toPath: "src/run-moved.ts", baseUpdatedAt: saved.updatedAt, clientId: "run-move" }),
      });
      assert.equal(moved.status, 200);
      const movedBody = await moved.json();
      assert.equal(movedBody.path, "src/run-moved.ts");
      assert.equal(movedBody.previousPath, "src/index.ts");
      assert.equal(files.get("src/run-moved.ts"), "export const savedForRun = true;\n");
      assert.equal(files.has("src/index.ts"), false);

      const deleted = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/files?project=proj-a&path=src/run-moved.ts`, {
        method: "DELETE",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ clientId: "run-delete" }),
      });
      assert.equal(deleted.status, 200);
      assert.deepEqual(await deleted.json(), { path: "src/run-moved.ts", kind: "deleted" });
      assert.equal(files.has("src/run-moved.ts"), false);

      const expectedFactory = `factory:alice:proj-a:${summary.runId}:https://git.example/team/proj-a.git:task/run-files:origin/main:${join(workspaceRoot, "alice", "proj-a")}`;
      assert.deepEqual(calls, [
        expectedFactory,
        "prepare",
        `inspect:${summary.runId}:`,
        expectedFactory,
        "prepare",
        `inspect:${summary.runId}:src/index.ts`,
        `read:${summary.runId}:src/index.ts`,
        expectedFactory,
        "prepare",
        `inspect:${summary.runId}:src/index.ts`,
        `write:${summary.runId}:src/index.ts:export const savedForRun = true;\n`,
        `inspect:${summary.runId}:src/index.ts`,
        `read:${summary.runId}:src/index.ts`,
        expectedFactory,
        "prepare",
        `inspect:${summary.runId}:src/index.ts`,
        `inspect:${summary.runId}:src/run-moved.ts`,
        `move:${summary.runId}:src/index.ts:src/run-moved.ts`,
        `inspect:${summary.runId}:src/run-moved.ts`,
        `read:${summary.runId}:src/run-moved.ts`,
        expectedFactory,
        "prepare",
        `inspect:${summary.runId}:src/run-moved.ts`,
        `delete:${summary.runId}:src/run-moved.ts`,
      ]);
    },
    {
      createExecutor: (cwd: string, context: { tenant: string; project: string; runId?: string; repo?: string; branch?: string; baseBranch?: string }) => {
        calls.push(`factory:${context.tenant}:${context.project}:${context.runId}:${context.repo}:${context.branch}:${context.baseBranch}:${cwd}`);
        return {
          async prepare(): Promise<void> {
            calls.push("prepare");
          },
          async inspectPath(path: string): Promise<any> {
            calls.push(`inspect:${context.runId}:${path}`);
            if (path === "") {
              return {
                path,
                kind: "directory",
                entries: [
                  { name: "README.md", path: "README.md", kind: "file", size: files.get("README.md")?.length, updatedAt: "2026-06-26T00:00:00.000Z" },
                  { name: "src", path: "src", kind: "directory", updatedAt: "2026-06-26T00:00:00.000Z" },
                ],
              };
            }
            if ((path === "src/index.ts" || path === "src/run-moved.ts") && files.has(path)) {
              return {
                path,
                kind: "file",
                size: files.get(path)?.length ?? 0,
                updatedAt: "2026-06-26T00:00:00.000Z",
              };
            }
            return { path, kind: "missing" };
          },
          async readFile(path: string): Promise<string> {
            calls.push(`read:${context.runId}:${path}`);
            return files.get(path) ?? "";
          },
          async writeFile(path: string, content: string): Promise<void> {
            calls.push(`write:${context.runId}:${path}:${content}`);
            files.set(path, content);
          },
          async deleteFile(path: string): Promise<void> {
            calls.push(`delete:${context.runId}:${path}`);
            files.delete(path);
          },
          async moveFile(fromPath: string, toPath: string): Promise<void> {
            calls.push(`move:${context.runId}:${fromPath}:${toPath}`);
            files.set(toPath, files.get(fromPath) ?? "");
            files.delete(fromPath);
          },
          async runCommand(command: string): Promise<{ stdout: string; stderr: string; exitCode: number }> {
            calls.push(`run:${context.runId}:${command}`);
            return { stdout: "", stderr: "", exitCode: 0 };
          },
        };
      },
    },
  );
});

test("HTTP harness blocks same-run workspace file writes while an isolated run is active", async () => {
  const workspaceRoot = await tempDir("loom-http-run-workspace-file-active-lock");

  await withServer(
    workspaceRoot,
    async (baseUrl) => {
      let activeRunId: string | undefined;
      try {
        const activeRun = await fetch(`${baseUrl}/runs`, {
          method: "POST",
          headers: { "content-type": "application/json" },
          body: JSON.stringify({
            async: true,
            tenant: "alice",
            project: "proj-a",
            goal: "hold active run workspace",
            script: [
              {
                message: "start long command",
                actions: [
                  {
                    toolName: "shell.exec",
                    input: { command: "sleep 5; printf active > active.txt" },
                  },
                ],
              },
              { message: "finish", finish: true },
            ],
            verify: ["test -f active.txt"],
            skills: ["coding"],
          }),
        });
        assert.equal(activeRun.status, 202);
        const active = await activeRun.json();
        assert.equal(active.status, "running");
        activeRunId = active.runId;

        const blocked = await fetch(`${baseUrl}/tenants/alice/runs/${active.runId}/files?project=proj-a`, {
          method: "POST",
          headers: { "content-type": "application/json" },
          body: JSON.stringify({
            path: "src/live.ts",
            content: "export const live = true;\n",
          }),
        });
        assert.equal(blocked.status, 409);
        assert.match((await blocked.json()).error, /active run/);

        const completedRun = await fetch(`${baseUrl}/runs`, {
          method: "POST",
          headers: { "content-type": "application/json" },
          body: JSON.stringify({
            tenant: "alice",
            project: "proj-a",
            goal: "prepare completed isolated run workspace",
            script: [{ message: "finish", finish: true }],
            verify: [],
            skills: ["coding"],
          }),
        });
        assert.equal(completedRun.status, 201);
        const completed = await completedRun.json();
        assert.equal(completed.status, "passed");

        const allowed = await fetch(`${baseUrl}/tenants/alice/runs/${completed.runId}/files?project=proj-a`, {
          method: "POST",
          headers: { "content-type": "application/json" },
          body: JSON.stringify({
            path: "src/completed.ts",
            content: "export const completed = true;\n",
          }),
        });
        assert.equal(allowed.status, 200);
        const body = await allowed.json();
        assert.equal(body.runId, undefined);
        assert.equal(body.path, "src/completed.ts");
        assert.equal(body.content, "export const completed = true;\n");
      } finally {
        if (activeRunId) {
          const cancel = await fetch(`${baseUrl}/tenants/alice/runs/${activeRunId}/cancel?project=proj-a`, {
            method: "POST",
            headers: { "content-type": "application/json" },
            body: JSON.stringify({ reason: "release active isolated run workspace" }),
          });
          assert.equal(cancel.status, 200);
        }
      }
    },
    {
      allowedTools: ["file.read", "file.write", "shell.exec", "git.diff", "verify.run"],
      runWorkspaceIsolation: "run",
    },
  );
});

