test("HTTP harness workspace diffs exclude tracked .loom internals", async () => {
  const workspaceRoot = await tempDir("loom-http-workspace-diff-loom");
  const projectRoot = join(workspaceRoot, "alice", "proj-a");
  await writeProjectRegistration(workspaceRoot, "alice", "proj-a");
  await mkdir(projectRoot, { recursive: true });
  await execFileAsync("git", ["init"], { cwd: projectRoot });
  await execFileAsync("git", ["config", "user.email", "loom@example.test"], { cwd: projectRoot });
  await execFileAsync("git", ["config", "user.name", "Loom Test"], { cwd: projectRoot });
  await writeFile(join(projectRoot, "README.md"), "# Before\n", "utf8");
  await mkdir(join(projectRoot, ".loom", "runs", "run-internal"), { recursive: true });
  await writeFile(join(projectRoot, ".loom", "runs", "run-internal", "summary.json"), "{\"internal\":\"before\"}\n", "utf8");
  await execFileAsync("git", ["add", "-A"], { cwd: projectRoot });
  await execFileAsync("git", ["commit", "-m", "baseline"], { cwd: projectRoot });
  await writeFile(join(projectRoot, "README.md"), "# After\n", "utf8");
  await writeFile(join(projectRoot, ".loom", "runs", "run-internal", "summary.json"), "{\"internal\":\"after\"}\n", "utf8");

  await withServer(
    workspaceRoot,
    async (baseUrl) => {
      const response = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/diff`);
      assert.equal(response.status, 200);
      const body = await response.json();
      assert.equal(body.exitCode, 0);
      assert.match(body.stdout, /README\.md/);
      assert.doesNotMatch(body.stdout, /\.loom/);
      assert.doesNotMatch(body.stdout, /internal/);
    },
    { allowedTools: ["git.diff"] },
  );
});

test("HTTP harness creates audited project workspace commits through git.commit", async () => {
  const workspaceRoot = await tempDir("loom-http-workspace-commit");
  const projectRoot = join(workspaceRoot, "alice", "proj-a");
  await writeProjectRegistration(workspaceRoot, "alice", "proj-a");
  await mkdir(projectRoot, { recursive: true });
  await execFileAsync("git", ["init"], { cwd: projectRoot });
  await execFileAsync("git", ["config", "user.email", "loom@example.test"], { cwd: projectRoot });
  await execFileAsync("git", ["config", "user.name", "Loom Test"], { cwd: projectRoot });
  await writeFile(join(projectRoot, "README.md"), "# Before\n", "utf8");
  await execFileAsync("git", ["add", "-A"], { cwd: projectRoot });
  await execFileAsync("git", ["commit", "-m", "baseline"], { cwd: projectRoot });
  await writeFile(join(projectRoot, "README.md"), "# After\n", "utf8");
  await mkdir(join(projectRoot, "src"), { recursive: true });
  await writeFile(join(projectRoot, "src", "index.ts"), "export const checkpoint = true;\n", "utf8");
  await mkdir(join(projectRoot, ".loom", "runs", "run-internal"), { recursive: true });
  await writeFile(join(projectRoot, ".loom", "runs", "run-internal", "summary.json"), "{\"internal\":true}\n", "utf8");

  await withServer(
    workspaceRoot,
    async (baseUrl) => {
      const created = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/commits`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ message: "workspace checkpoint", clientId: "dash-commit" }),
      });
      assert.equal(created.status, 201);
      const body = await created.json();
      assert.equal(body.message, "workspace checkpoint");
      assert.equal(body.command, "git add -A -- . ':(exclude).loom' && (git reset -q -- .loom 2>/dev/null || true) && git commit --only -m 'workspace checkpoint' -- . ':(exclude).loom'");
      assert.match(body.commit, /^[0-9a-f]{7,}$/);
      assert.equal(body.exitCode, 0);

      const log = await execFileAsync("git", ["log", "--format=%s", "-1"], { cwd: projectRoot });
      assert.equal(log.stdout.trim(), "workspace checkpoint");
      const committedFiles = await execFileAsync("git", ["show", "--name-only", "--format=", "HEAD"], { cwd: projectRoot });
      assert.deepEqual(committedFiles.stdout.split("\n").filter(Boolean).sort(), ["README.md", "src/index.ts"]);
      const status = await execFileAsync("git", ["status", "--porcelain"], { cwd: projectRoot });
      assert.match(status.stdout, /\?\? \.loom\//);

      const audit = await fetch(`${baseUrl}/tenants/alice/audit?project=proj-a`);
      assert.equal(audit.status, 200);
      const auditEvents = await audit.json();
      const event = auditEvents.find((entry: any) => entry.type === "workspace_commit_created");
      assert.ok(event);
      assert.equal(event.data.project, "proj-a");
      assert.equal(event.data.message, "workspace checkpoint");
      assert.equal(event.data.commit, body.commit);
      assert.equal(event.data.clientId, "dash-commit");

      const empty = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/commits`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ message: "empty checkpoint" }),
      });
      assert.equal(empty.status, 400);
      assert.match((await empty.json()).error, /no workspace changes/);
    },
    { allowedTools: ["file.read", "file.write", "git.diff", "git.commit", "verify.run"] },
  );
});

test("HTTP harness creates run-scoped workspace commits with run executor context", async () => {
  const workspaceRoot = await tempDir("loom-http-run-workspace-commit");
  const calls: string[] = [];

  await withServer(
    workspaceRoot,
    async (baseUrl) => {
      const createdRun = await fetch(`${baseUrl}/runs`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({
          tenant: "alice",
          project: "proj-a",
          repo: "https://git.example/team/proj-a.git",
          branch: "task/run-commit",
          baseBranch: "origin/main",
          goal: "create run-scoped workspace",
          script: [{ message: "finish", finish: true }],
          verify: [],
          skills: ["coding"],
        }),
      });
      assert.equal(createdRun.status, 201);
      const summary = await createdRun.json();
      calls.length = 0;

      const createdCommit = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/commits?project=proj-a`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ message: "run checkpoint", clientId: "workbench-commit" }),
      });
      assert.equal(createdCommit.status, 201);
      const commit = await createdCommit.json();
      assert.equal(commit.message, "run checkpoint");
      assert.equal(commit.commit, "abc1234");
      assert.equal(commit.exitCode, 0);

      const expectedFactory = `factory:alice:proj-a:${summary.runId}:https://git.example/team/proj-a.git:task/run-commit:origin/main:${join(workspaceRoot, "alice", "proj-a")}`;
      assert.deepEqual(calls, [
        expectedFactory,
        `prepare:${summary.runId}`,
        `run:${summary.runId}:git add -A -- . ':(exclude).loom':120000`,
        `run:${summary.runId}:(git reset -q -- .loom 2>/dev/null || true):120000`,
        `run:${summary.runId}:git diff --cached --quiet -- . ':(exclude).loom':120000`,
        `run:${summary.runId}:git commit --only -m 'run checkpoint' -- . ':(exclude).loom':120000`,
        `run:${summary.runId}:git rev-parse --short HEAD:120000`,
      ]);

      const audit = await fetch(`${baseUrl}/tenants/alice/audit?project=proj-a`);
      assert.equal(audit.status, 200);
      const auditEvents = await audit.json();
      const event = auditEvents.find((entry: any) => entry.type === "workspace_commit_created");
      assert.ok(event);
      assert.equal(event.data.runId, summary.runId);
      assert.equal(event.data.commit, "abc1234");
      assert.equal(event.data.clientId, "workbench-commit");
    },
    {
      allowedTools: ["file.read", "file.write", "git.diff", "git.commit", "verify.run"],
      createExecutor: (cwd: string, context: { tenant: string; project: string; runId?: string; repo?: string; branch?: string; baseBranch?: string }) => {
        calls.push(`factory:${context.tenant}:${context.project}:${context.runId}:${context.repo}:${context.branch}:${context.baseBranch}:${cwd}`);
        return {
          async prepare(): Promise<void> {
            calls.push(`prepare:${context.runId}`);
          },
          async inspectPath(path: string): Promise<any> {
            return { path, kind: "missing" };
          },
          async readFile(): Promise<string> {
            return "";
          },
          async writeFile(): Promise<void> {},
          async runCommand(command: string, timeoutMs?: number): Promise<{ stdout: string; stderr: string; exitCode: number }> {
            calls.push(`run:${context.runId}:${command}:${timeoutMs}`);
            if (command === "(git reset -q -- .loom 2>/dev/null || true)") return { stdout: "", stderr: "", exitCode: 0 };
            if (command === "git diff --cached --quiet -- . ':(exclude).loom'") return { stdout: "", stderr: "", exitCode: 1 };
            if (command === "git commit --only -m 'run checkpoint' -- . ':(exclude).loom'") return { stdout: "[task/run-commit abc1234] run checkpoint\n", stderr: "", exitCode: 0 };
            if (command === "git rev-parse --short HEAD") return { stdout: "abc1234\n", stderr: "", exitCode: 0 };
            return { stdout: "", stderr: "", exitCode: 0 };
          },
        };
      },
    },
  );
});

