test("HTTP harness derives unique run workspace pull request branches from shared project defaults", async () => {
  const workspaceRoot = await tempDir("loom-http-run-workspace-pr-unique-branches");
  const pullRequests: any[] = [];

  await withServer(
    workspaceRoot,
    async (baseUrl) => {
      const runIds: string[] = [];
      for (const goal of ["prepare first concurrent handoff", "prepare second concurrent handoff"]) {
        const createdRun = await fetch(`${baseUrl}/runs`, {
          method: "POST",
          headers: { "content-type": "application/json" },
          body: JSON.stringify({
            tenant: "alice",
            project: "proj-a",
            goal,
            script: [{ message: "finish", finish: true }],
            verify: [],
            skills: ["coding"],
          }),
        });
        assert.equal(createdRun.status, 201);
        const summary = await createdRun.json();
        assert.equal(summary.status, "passed");
        runIds.push(summary.runId);
      }

      const defaults = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/source-defaults`, {
        method: "PUT",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({
          repo: "https://git.example/team/proj-a.git",
          branch: "task/shared",
          baseBranch: "origin/main",
          issue: "team/proj-a#46",
        }),
      });
      assert.equal(defaults.status, 200);

      for (const [index, runId] of runIds.entries()) {
        const createdPr = await fetch(`${baseUrl}/tenants/alice/runs/${runId}/pull-requests?project=proj-a`, {
          method: "POST",
          headers: { "content-type": "application/json" },
          body: JSON.stringify({
            title: `Concurrent handoff ${index + 1}`,
            commit: `cafe00${index}`,
            push: false,
          }),
        });
        assert.equal(createdPr.status, 201);
        const body = await createdPr.json();
        assert.equal(body.branch, `task/shared/${runId}`);
      }

      assert.deepEqual(pullRequests.map((request) => request.branch), [
        `task/shared/${runIds[0]}`,
        `task/shared/${runIds[1]}`,
      ]);
      assert.notEqual(pullRequests[0].branch, pullRequests[1].branch);
    },
    {
      allowedTools: ["file.read", "file.write", "git.diff", "git.commit", "git.pr", "verify.run"],
      runWorkspaceIsolation: "run",
      workspacePullRequestReporter: async (request: any) => {
        pullRequests.push({ runId: request.runId, branch: request.branch });
        return { index: pullRequests.length, url: `https://git.example/team/proj-a/pulls/${pullRequests.length}` };
      },
      createExecutor: (_cwd: string, _context: { tenant: string; project: string; runId?: string; repo?: string; branch?: string; baseBranch?: string }) => ({
        async prepare(): Promise<void> {},
        async inspectPath(path: string): Promise<any> {
          return { path, kind: "missing" };
        },
        async readFile(): Promise<string> {
          return "";
        },
        async writeFile(): Promise<void> {},
        async runCommand(): Promise<{ stdout: string; stderr: string; exitCode: number }> {
          return { stdout: "", stderr: "", exitCode: 0 };
        },
      }),
    },
  );
});

test("HTTP harness allows run workspace pull request handoffs while another isolated run is active", async () => {
  const workspaceRoot = await tempDir("loom-http-run-workspace-pr-during-active-run");
  const pullRequests: any[] = [];

  await withServer(
    workspaceRoot,
    async (baseUrl) => {
      let activeRunId: string | undefined;
      try {
        const activeRun = await fetch(`${baseUrl}/runs`, {
          method: "POST",
          headers: { "content-type": "application/json" },
          body: JSON.stringify({
            async: true,
            tenant: "alice",
            project: "proj-a",
            goal: "hold one isolated workspace",
            script: [
              {
                message: "start long command",
                actions: [
                  {
                    toolName: "shell.exec",
                    input: { command: "sleep 5; printf active > active.txt" },
                  },
                ],
              },
              { message: "finish", finish: true },
            ],
            verify: ["test -f active.txt"],
            skills: ["coding"],
          }),
        });
        assert.equal(activeRun.status, 202);
        const active = await activeRun.json();
        assert.equal(active.status, "running");
        activeRunId = active.runId;

        const completedRun = await fetch(`${baseUrl}/runs`, {
          method: "POST",
          headers: { "content-type": "application/json" },
          body: JSON.stringify({
            tenant: "alice",
            project: "proj-a",
            issue: "team/proj-a#47",
            branch: "task/completed-while-active",
            baseBranch: "origin/main",
            goal: "prepare completed isolated handoff",
            script: [{ message: "finish", finish: true }],
            verify: [],
            skills: ["coding"],
          }),
        });
        assert.equal(completedRun.status, 201);
        const completed = await completedRun.json();
        assert.equal(completed.status, "passed");

        const handoff = await fetch(`${baseUrl}/tenants/alice/runs/${completed.runId}/pull-requests?project=proj-a`, {
          method: "POST",
          headers: { "content-type": "application/json" },
          body: JSON.stringify({
            title: "Completed handoff while active run continues",
            commit: "cafe123",
            push: false,
          }),
        });
        assert.equal(handoff.status, 201);
        const body = await handoff.json();
        assert.equal(body.runId, completed.runId);
        assert.equal(body.branch, `task/completed-while-active/${completed.runId}`);
        assert.equal(body.pullRequestIndex, 21);

        assert.deepEqual(pullRequests, [
          {
            runId: completed.runId,
            branch: `task/completed-while-active/${completed.runId}`,
            commit: "cafe123",
            push: false,
          },
        ]);
      } finally {
        if (activeRunId) {
          const cancel = await fetch(`${baseUrl}/tenants/alice/runs/${activeRunId}/cancel?project=proj-a`, {
            method: "POST",
            headers: { "content-type": "application/json" },
            body: JSON.stringify({ reason: "release active isolated run" }),
          });
          assert.equal(cancel.status, 200);
        }
      }
    },
    {
      allowedTools: ["file.read", "file.write", "shell.exec", "git.diff", "git.commit", "git.pr", "verify.run"],
      runWorkspaceIsolation: "run",
      workspacePullRequestReporter: async (request: any) => {
        pullRequests.push({
          runId: request.runId,
          branch: request.branch,
          commit: request.commit,
          push: request.push,
        });
        return { index: 21, url: "https://git.example/team/proj-a/pulls/21" };
      },
    },
  );
});

test("HTTP harness attaches run workspace pull request handoffs to review gates", async () => {
  const workspaceRoot = await tempDir("loom-http-run-workspace-pr");
  const calls: string[] = [];
  const pullRequests: any[] = [];

  await withServer(
    workspaceRoot,
    async (baseUrl) => {
      const createdRun = await fetch(`${baseUrl}/runs`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({
          tenant: "alice",
          project: "proj-a",
          repo: "https://git.example/team/proj-a.git",
          branch: "task/run-pr",
          baseBranch: "origin/main",
          issue: "team/proj-a#43",
          goal: "prepare run handoff",
          script: [{ message: "finish", finish: true }],
          verify: [],
          reviewer: ["printf workspace-reviewer-note"],
          skills: ["coding"],
          clientId: "dashboard-run",
        }),
      });
      assert.equal(createdRun.status, 201);
      const summary = await createdRun.json();
      assert.equal(summary.status, "passed");
      calls.length = 0;

      const createdPr = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/pull-requests?project=proj-a`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ reviewRequired: true, deploymentRequired: true, clientId: "workbench-pr" }),
      });
      assert.equal(createdPr.status, 201);
      const pr = await createdPr.json();
      assert.equal(pr.runId, summary.runId);
      assert.equal(pr.issue, "team/proj-a#43");
      assert.equal(pr.branch, "task/run-pr");
      assert.equal(pr.baseBranch, "origin/main");
      assert.equal(pr.commit, "def5678");
      assert.equal(pr.pullRequestIndex, 13);
      assert.equal(pr.reviewRequired, true);
      assert.equal(pr.deploymentRequired, true);

      const expectedFactory = `factory:alice:proj-a:${summary.runId}:https://git.example/team/proj-a.git:task/run-pr:origin/main:${join(workspaceRoot, "alice", "proj-a")}`;
      assert.deepEqual(calls, [
        expectedFactory,
        `prepare:${summary.runId}`,
        `run:${summary.runId}:git rev-parse --short HEAD:120000`,
        `run:${summary.runId}:git push -u origin HEAD:task/run-pr:120000`,
      ]);
      assert.equal(pullRequests[0].runId, summary.runId);
      assert.equal(pullRequests[0].issue, "team/proj-a#43");
      assert.equal(pullRequests[0].branch, "task/run-pr");
      assert.equal(pullRequests[0].baseBranch, "origin/main");
      assert.match(pullRequests[0].body, /Requester: dashboard-run/);
      assert.match(pullRequests[0].body, new RegExp(`Review summary: https://loom\\.example/tenants/alice/runs/${summary.runId}/review-summary\\?project=proj-a`));
      assert.match(pullRequests[0].body, new RegExp(`Handoff package: https://loom\\.example/tenants/alice/runs/${summary.runId}/handoff-package\\?project=proj-a`));
      assert.match(pullRequests[0].body, new RegExp(`Follow-up runs: https://loom\\.example/tenants/alice/runs/${summary.runId}/handoff-runs\\?project=proj-a`));
      assert.match(pullRequests[0].body, /Reviewer: passed \(exit 0\)/);
      assert.match(pullRequests[0].body, /Reviewer commands: `printf workspace-reviewer-note`/);

      const readSummary = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}?project=proj-a`);
      assert.equal(readSummary.status, 200);
      const saved = await readSummary.json();
      assert.equal(saved.status, "review_required");
      assert.deepEqual(saved.review, { required: true, status: "pending" });
      assert.deepEqual(saved.deployment, { required: true, status: "pending" });
      assert.equal(saved.metadata.pullRequestIndex, 13);
      assert.equal(saved.metadata.pullRequestUrl, "https://git.example/team/proj-a/pulls/13");

      const events = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/events?project=proj-a`);
      assert.equal(events.status, 200);
      const body = await events.json();
      assert.ok(body.some((event: any) =>
        event.type === "external_effect" &&
        event.data.kind === "pull_request" &&
        event.data.pullRequestIndex === 13 &&
        event.data.clientId === "workbench-pr" &&
        event.data.requester?.clientId === "dashboard-run"
      ));
      assert.ok(body.some((event: any) => event.type === "review_gate" && event.data.status === "pending" && event.data.clientId === "workbench-pr"));
      assert.ok(body.some((event: any) => event.type === "deployment_gate" && event.data.status === "pending" && event.data.clientId === "workbench-pr"));

      const review = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/review?project=proj-a`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ decision: "approved", note: "review ok", clientId: "workbench-review" }),
      });
      assert.equal(review.status, 200);
      const reviewed = await review.json();
      assert.equal(reviewed.status, "deployment_required");
      assert.deepEqual(reviewed.deployment, { required: true, status: "pending" });

      const audit = await fetch(`${baseUrl}/tenants/alice/audit?project=proj-a`);
      assert.equal(audit.status, 200);
      const auditEvent = (await audit.json()).find((entry: any) => entry.type === "workspace_pull_request_created");
      assert.ok(auditEvent);
      assert.equal(auditEvent.data.runId, summary.runId);
      assert.equal(auditEvent.data.pullRequestIndex, 13);
      assert.equal(auditEvent.data.reviewRequired, true);
      assert.equal(auditEvent.data.deploymentRequired, true);
    },
    {
      allowedTools: ["file.read", "file.write", "git.diff", "git.commit", "git.pr", "verify.run"],
      publicUrl: "https://loom.example",
      workspacePullRequestReporter: async (request: any) => {
        pullRequests.push(request);
        return { index: 13, url: "https://git.example/team/proj-a/pulls/13" };
      },
      createExecutor: (cwd: string, context: { tenant: string; project: string; runId?: string; repo?: string; branch?: string; baseBranch?: string }) => {
        calls.push(`factory:${context.tenant}:${context.project}:${context.runId}:${context.repo}:${context.branch}:${context.baseBranch}:${cwd}`);
        return {
          async prepare(): Promise<void> {
            calls.push(`prepare:${context.runId}`);
          },
          async inspectPath(path: string): Promise<any> {
            return { path, kind: "missing" };
          },
          async readFile(): Promise<string> {
            return "";
          },
          async writeFile(): Promise<void> {},
          async runCommand(command: string, timeoutMs?: number): Promise<{ stdout: string; stderr: string; exitCode: number }> {
            calls.push(`run:${context.runId}:${command}:${timeoutMs}`);
            if (command === "git rev-parse --short HEAD") return { stdout: "def5678\n", stderr: "", exitCode: 0 };
            return { stdout: "pushed\n", stderr: "", exitCode: 0 };
          },
        };
      },
    },
  );
});

