test("HTTP harness truncates persisted workspace session output events", async () => {
  const workspaceRoot = await tempDir("loom-http-workspace-session-truncate");
  await writeProjectRegistration(workspaceRoot, "alice", "proj-a");
  const data = "s".repeat(70 * 1024);

  await withServer(
    workspaceRoot,
    async (baseUrl) => {
      const create = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/sessions`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ command: "sh" }),
      });
      assert.equal(create.status, 201);
      const session = await create.json();

      const eventsUrl = `${baseUrl}/tenants/alice/projects/proj-a/sessions/${session.sessionId}/events`;
      const events = await pollJson(eventsUrl, (body) => body.some((event) => event.type === "stdout" && event.dataTruncated === true));
      const output = events.find((event) => event.type === "stdout");
      assert.equal(output.data.length, 64 * 1024);
      assert.equal(output.data[0], "s");
      assert.equal(output.data.at(-1), "s");
      assert.equal(output.dataTruncated, true);
      assert.equal(output.dataBytes, Buffer.byteLength(data, "utf8"));

      const stop = await fetch(`${baseUrl}/tenants/alice/projects/proj-a/sessions/${session.sessionId}/stop`, {
        method: "POST",
      });
      assert.equal(stop.status, 200);
    },
    {
      allowedTools: ["file.read", "file.write", "shell.exec", "git.diff", "verify.run"],
      createExecutor: () => ({
        async prepare(): Promise<void> {},
        async inspectPath(path: string): Promise<any> {
          return { path, kind: "missing" };
        },
        async readFile(): Promise<string> {
          return "";
        },
        async writeFile(): Promise<void> {},
        async runCommand(): Promise<{ stdout: string; stderr: string; exitCode: number }> {
          return { stdout: "", stderr: "", exitCode: 0 };
        },
        startSession(): any {
          const exitListeners: Array<(event: { exitCode: number }) => void> = [];
          return {
            onOutput(listener: (event: { stream: "stdout" | "stderr"; data: string }) => void): () => void {
              setTimeout(() => listener({ stream: "stdout", data }), 0);
              return () => undefined;
            },
            onExit(listener: (event: { exitCode: number }) => void): () => void {
              exitListeners.push(listener);
              return () => undefined;
            },
            async write(): Promise<void> {},
            async stop(): Promise<void> {
              for (const listener of exitListeners) listener({ exitCode: 0 });
            },
          };
        },
      }),
    },
  );
});

