test("HTTP harness persists workspace session events and lists them after restart", async () => {
  const workspaceRoot = await tempDir("loom-http-workspace-session-persist");
  await writeProjectRegistration(workspaceRoot, "alice", "default");
  let sessionId = "";

  await withServer(
    workspaceRoot,
    async (baseUrl) => {
      const create = await fetch(`${baseUrl}/tenants/alice/projects/default/sessions`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ command: "sh" }),
      });
      assert.equal(create.status, 201);
      const session = await create.json();
      sessionId = session.sessionId;

      const input = await fetch(`${baseUrl}/tenants/alice/projects/default/sessions/${sessionId}/input`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ input: "echo persisted-session\nexit\n" }),
      });
      assert.equal(input.status, 200);

      const eventsUrl = `${baseUrl}/tenants/alice/projects/default/sessions/${sessionId}/events`;
      await pollJson(eventsUrl, (body) => body.some((event) => event.type === "exit" && event.exitCode === 0));
    },
    { allowedTools: ["file.read", "file.write", "shell.exec", "git.diff", "verify.run"] },
  );

  await withServer(workspaceRoot, async (baseUrl) => {
    const list = await fetch(`${baseUrl}/tenants/alice/projects/default/sessions`);
    assert.equal(list.status, 200);
    const sessions = await list.json();
    assert.deepEqual(
      sessions.map((session) => ({ sessionId: session.sessionId, status: session.status, exitCode: session.exitCode })),
      [{ sessionId, status: "exited", exitCode: 0 }],
    );

    const events = await fetch(`${baseUrl}/tenants/alice/projects/default/sessions/${sessionId}/events`);
    assert.equal(events.status, 200);
    const body = await events.json();
    assert.ok(body.some((event) => event.type === "stdout" && event.data === "persisted-session\n"));
    assert.ok(body.some((event) => event.type === "exit" && event.exitCode === 0));

    const projectsResponse = await fetch(`${baseUrl}/tenants/alice/projects`);
    const projectsText = await projectsResponse.text();
    assert.equal(projectsResponse.status, 200, projectsText);
    const projects = JSON.parse(projectsText);
    const projectSummary = projects.find((item: any) => item.project === "default");
    assert.equal(projectSummary.latestWorkspaceSession.sessionId, sessionId);
    assert.equal(projectSummary.latestWorkspaceSession.command, "sh");
    assert.equal(projectSummary.latestWorkspaceSession.status, "exited");
    assert.equal(projectSummary.latestWorkspaceSession.exitCode, 0);
    assert.equal(projectSummary.latestWorkspaceSession.route, "project");
    assert.equal(projectSummary.activityAt, projectSummary.latestWorkspaceSession.endedAt);

    const projectDetailResponse = await fetch(`${baseUrl}/tenants/alice/projects/default`);
    const projectDetailText = await projectDetailResponse.text();
    assert.equal(projectDetailResponse.status, 200, projectDetailText);
    const projectDetail = JSON.parse(projectDetailText);
    assert.equal(projectDetail.latestWorkspaceSession.sessionId, sessionId);
  });
});

test("HTTP harness persisted workspace session events ignore unreadable and invalid transcript lines", async () => {
  const workspaceRoot = await tempDir("loom-http-workspace-session-events-corrupt");
  const sessionDir = join(workspaceRoot, "alice", "default", ".loom", "sessions", "session-a");
  await mkdir(sessionDir, { recursive: true });
  await writeFile(
    join(sessionDir, "events.jsonl"),
    [
      JSON.stringify({ seq: 1, ts: "2026-06-26T00:00:00.000Z", type: "start", data: "sh" }),
      "{not json",
      JSON.stringify({ seq: 2, ts: "2026-06-26T00:00:01.000Z", type: "unknown", data: "skip" }),
      JSON.stringify({ seq: "3", ts: "2026-06-26T00:00:02.000Z", type: "stdout", data: "skip" }),
      JSON.stringify({ seq: 3, ts: "2026-06-26T00:00:03.000Z", type: "stdout", data: "still here\n" }),
      JSON.stringify({ seq: 4, ts: "2026-06-26T00:00:04.000Z", type: "exit", exitCode: 0 }),
      "",
    ].join("\n"),
    "utf8",
  );

  await withServer(workspaceRoot, async (baseUrl) => {
    const events = await fetch(`${baseUrl}/tenants/alice/projects/default/sessions/session-a/events`);
    const eventsText = await events.text();
    assert.equal(events.status, 200, eventsText);
    assert.deepEqual(
      JSON.parse(eventsText).map((event: any) => ({ seq: event.seq, type: event.type })),
      [
        { seq: 1, type: "start" },
        { seq: 3, type: "stdout" },
        { seq: 4, type: "exit" },
      ],
    );

    const stream = await fetch(`${baseUrl}/tenants/alice/projects/default/sessions/session-a/events/stream?after=0`, {
      headers: { "last-event-id": "1" },
    });
    assert.equal(stream.status, 200);
    const streamText = await stream.text();
    assert.doesNotMatch(streamText, /"seq":1/);
    assert.match(streamText, /id: 3/);
    assert.match(streamText, /id: 4/);
  });
});

