test("HTTP harness enforces workspace session caps across server instances", async () => {
  const workspaceRoot = await tempDir("loom-http-cross-server-workspace-session-cap");
  await writeProjectRegistration(workspaceRoot, "alice", "proj-a");
  await writeProjectRegistration(workspaceRoot, "bob", "proj-a");
  const calls: string[] = [];
  const options = {
    allowedTools: ["file.read", "file.write", "shell.exec", "git.diff", "verify.run"],
    maxWorkspaceSessions: 1,
    maxTenantWorkspaceSessions: 5,
    createExecutor: (cwd: string, context: { tenant: string; project: string; runId: string }) => {
      calls.push(`factory:${context.tenant}:${context.project}:${context.runId}:${cwd}`);
      return fakeSessionExecutor(calls, context.runId);
    },
  };

  await withServer(
    workspaceRoot,
    async (firstBaseUrl) => {
      await withServer(
        workspaceRoot,
        async (secondBaseUrl) => {
          const first = await fetch(`${firstBaseUrl}/tenants/alice/projects/proj-a/sessions`, {
            method: "POST",
            headers: { "content-type": "application/json" },
            body: JSON.stringify({ command: "sh" }),
          });
          assert.equal(first.status, 201);
          const firstSession = await first.json();
          const claimPath = join(workspaceRoot, ".loom", "admission", "workspace-sessions", `${firstSession.sessionId}.json`);
          const claim = JSON.parse(await readFile(claimPath, "utf8"));
          assert.deepEqual(
            {
              schemaVersion: claim.schemaVersion,
              tenant: claim.tenant,
              project: claim.project,
              sessionId: claim.sessionId,
              limit: claim.limit,
            },
            {
              schemaVersion: 1,
              tenant: "alice",
              project: "proj-a",
              sessionId: firstSession.sessionId,
              limit: 1,
            },
          );

          const second = await fetch(`${secondBaseUrl}/tenants/bob/projects/proj-a/sessions`, {
            method: "POST",
            headers: { "content-type": "application/json" },
            body: JSON.stringify({ command: "sh" }),
          });
          const secondText = await second.text();
          if (second.status === 201) {
            const secondSession = JSON.parse(secondText);
            const stopSecond = await fetch(`${secondBaseUrl}/tenants/bob/projects/proj-a/sessions/${secondSession.sessionId}/stop`, {
              method: "POST",
            });
            assert.equal(stopSecond.status, 200);
            const stopFirst = await fetch(`${firstBaseUrl}/tenants/alice/projects/proj-a/sessions/${firstSession.sessionId}/stop`, {
              method: "POST",
            });
            assert.equal(stopFirst.status, 200);
            assert.fail(`expected cross-server workspace session cap conflict, got ${secondText}`);
          }
          assert.equal(second.status, 409, secondText);
          assert.match(JSON.parse(secondText).error, /active workspace session limit/);
          assert.ok(!calls.some((call) => call.includes("bob:proj-a")));

          const stopFirst = await fetch(`${firstBaseUrl}/tenants/alice/projects/proj-a/sessions/${firstSession.sessionId}/stop`, {
            method: "POST",
          });
          assert.equal(stopFirst.status, 200);
          await pollMissingFile(claimPath);
        },
        options,
      );
    },
    options,
  );
});

