test("HTTP harness caps active runs per tenant", async () => {
  const workspaceRoot = await tempDir("loom-http-tenant-run-cap");

  await withServer(
    workspaceRoot,
    async (baseUrl) => {
      const first = await fetch(`${baseUrl}/runs`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({
          async: true,
          tenant: "alice",
          project: "proj-a",
          goal: "hold tenant run slot",
          script: [
            {
              message: "start a long command",
              actions: [
                {
                  toolName: "shell.exec",
                  input: { command: "sleep 1; printf done > first.txt" },
                },
              ],
            },
            { message: "finish", finish: true },
          ],
          verify: ["test -f first.txt"],
          skills: ["coding"],
        }),
      });
      assert.equal(first.status, 202);
      const running = await first.json();

      const status = await fetch(`${baseUrl}/status`);
      assert.equal(status.status, 200);
      const statusBody = await status.json();
      assert.equal(statusBody.resources.activeRuns, 1);
      assert.equal(statusBody.limits.maxTenantActiveRuns, 1);

      const aliceSecond = await fetch(`${baseUrl}/runs`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({
          tenant: "alice",
          project: "proj-b",
          goal: "blocked by tenant run cap",
          script: [{ message: "finish", finish: true }],
          verify: [],
          skills: ["coding"],
        }),
      });
      assert.equal(aliceSecond.status, 409);
      assert.match((await aliceSecond.json()).error, /active run tenant limit/);

      const bobRun = await fetch(`${baseUrl}/runs`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({
          tenant: "bob",
          project: "proj-a",
          goal: "different tenant can run",
          script: [{ message: "finish", finish: true }],
          verify: [],
          skills: ["coding"],
        }),
      });
      assert.equal(bobRun.status, 201);

      const cancel = await fetch(`${baseUrl}/tenants/alice/runs/${running.runId}/cancel?project=proj-a`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ reason: "release tenant run cap" }),
      });
      assert.equal(cancel.status, 200);

      const afterCancel = await fetch(`${baseUrl}/runs`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({
          tenant: "alice",
          project: "proj-b",
          goal: "run after tenant slot release",
          script: [{ message: "finish", finish: true }],
          verify: [],
          skills: ["coding"],
        }),
      });
      assert.equal(afterCancel.status, 201);
    },
    {
      allowedTools: ["file.read", "file.write", "shell.exec", "git.diff", "verify.run"],
      maxTenantActiveRuns: 1,
    },
  );
});

