test("HTTP harness skips auto-abandon for cross-server active runs with live claims", async () => {
  const workspaceRoot = await tempDir("loom-http-skip-remote-active-auto-abandon");
  const options = {
    allowedTools: ["file.read", "file.write", "shell.exec", "git.diff", "verify.run"],
    runLeaseTtlMs: 10_000,
  };

  await withServer(
    workspaceRoot,
    async (firstBaseUrl) => {
      const create = await fetch(`${firstBaseUrl}/runs`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({
          async: true,
          tenant: "alice",
          project: "proj-a",
          goal: "hold remote active run during stale cleanup",
          script: [
            {
              message: "start a long command",
              actions: [
                {
                  toolName: "shell.exec",
                  input: { command: "sleep 5; printf done > first.txt" },
                },
              ],
            },
            { message: "finish", finish: true },
          ],
          verify: ["test -f first.txt"],
          skills: ["coding"],
        }),
      });
      assert.equal(create.status, 202);
      const running = await create.json();
      assert.equal(running.status, "running");
      const runDir = join(workspaceRoot, "alice", "proj-a", ".loom", "runs", running.runId);
      const statusPath = join(runDir, "status.json");
      const staleState = JSON.parse(await readFile(statusPath, "utf8"));
      const heartbeatAt = new Date(Date.now() - 20_000).toISOString();
      const leaseExpiresAt = new Date(Date.now() - 10_000).toISOString();
      await writeFile(statusPath, JSON.stringify({
        ...staleState,
        heartbeatAt,
        leaseExpiresAt,
      }, null, 2) + "\n", "utf8");

      try {
        await withServer(
          workspaceRoot,
          async (secondBaseUrl) => {
            const statusBody = await pollJson(`${secondBaseUrl}/status`, (body) => body.resources.staleRunCleanup?.status === "completed");
            assert.equal(statusBody.resources.staleRunCleanup.scannedRunningRuns, 1);
            assert.equal(statusBody.resources.staleRunCleanup.abandonedStaleRuns, 0);
            assert.equal(statusBody.resources.staleRunCleanup.skippedRunningRuns, 1);
            assert.deepEqual(statusBody.resources.orphanedRunningRunDetails, []);
            assert.equal(statusBody.resources.activeRuns, 1);
          },
          {
            ...options,
            autoAbandonStaleRuns: true,
          },
        );
      } finally {
        let cancel = await fetch(`${firstBaseUrl}/tenants/alice/runs/${running.runId}/cancel?project=proj-a`, {
          method: "POST",
          headers: { "content-type": "application/json" },
          body: JSON.stringify({ reason: "release remote active cleanup guard" }),
        }).catch(() => undefined);
        if (cancel?.status !== 200) {
          const now = new Date().toISOString();
          await writeFile(statusPath, JSON.stringify({
            ...staleState,
            heartbeatAt: now,
            leaseExpiresAt: new Date(Date.parse(now) + 10_000).toISOString(),
          }, null, 2) + "\n", "utf8");
          cancel = await fetch(`${firstBaseUrl}/tenants/alice/runs/${running.runId}/cancel?project=proj-a`, {
            method: "POST",
            headers: { "content-type": "application/json" },
            body: JSON.stringify({ reason: "release remote active cleanup guard" }),
          }).catch(() => undefined);
        }
        if (cancel?.status === 200) {
          await pollJson(`${firstBaseUrl}/tenants/alice/runs/${running.runId}?project=proj-a`, (body) => body.status === "cancelled");
        }
      }
    },
    options,
  );
});

test("HTTP harness rejects stale abandon for active or unleased persisted running runs", async () => {
  const workspaceRoot = await tempDir("loom-http-reject-abandon-stale-running");
  const heartbeatAt = new Date().toISOString();
  const leaseExpiresAt = new Date(Date.now() + 60_000).toISOString();
  await writeRunningStatus(workspaceRoot, "alice", "proj-a", "leased-run", { heartbeatAt, leaseExpiresAt });
  await writeRunningStatus(workspaceRoot, "alice", "proj-b", "unleased-run");

  await withServer(workspaceRoot, async (baseUrl) => {
    const leased = await fetch(`${baseUrl}/tenants/alice/runs/leased-run/abandon-stale?project=proj-a`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ reason: "not stale" }),
    });
    assert.equal(leased.status, 409);
    assert.match((await leased.json()).error, /lease is still active/);

    const unleased = await fetch(`${baseUrl}/tenants/alice/runs/unleased-run/abandon-stale?project=proj-b`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ reason: "missing lease" }),
    });
    assert.equal(unleased.status, 409);
    assert.match((await unleased.json()).error, /lease is still active/);
  });
});

test("HTTP harness can abandon a persisted running run after restart", async () => {
  const workspaceRoot = await tempDir("loom-http-abandon-running");
  await writeRunningStatus(workspaceRoot, "alice", "proj-a", "stale-run");

  await withServer(workspaceRoot, async (baseUrl) => {
    const abandon = await fetch(`${baseUrl}/tenants/alice/runs/stale-run/abandon?project=proj-a`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ reason: "server restarted before completion" }),
    });
    assert.equal(abandon.status, 200);
    const abandoned = await abandon.json();
    assert.equal(abandoned.status, "cancelled");

    const events = await fetch(`${baseUrl}/tenants/alice/runs/stale-run/events?project=proj-a`);
    assert.equal(events.status, 200);
    const body = await events.json();
    assert.ok(body.some((event) => event.type === "cancel" && event.data.reason === "server restarted before completion"));
    assert.ok(body.some((event) => event.type === "finish" && event.data.status === "cancelled"));

    const response = await fetch(`${baseUrl}/runs`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        tenant: "alice",
        project: "proj-a",
        goal: "run after abandon",
        script: [{ message: "finish", finish: true }],
        verify: [],
        skills: ["coding"],
      }),
    });
    assert.equal(response.status, 201);
    assert.equal((await response.json()).status, "passed");
  });
});

test("HTTP harness rejects abandoning cross-server active runs", async () => {
  const workspaceRoot = await tempDir("loom-http-reject-remote-active-abandon");

  await withServer(
    workspaceRoot,
    async (firstBaseUrl) => {
      await withServer(
        workspaceRoot,
        async (secondBaseUrl) => {
          const create = await fetch(`${firstBaseUrl}/runs`, {
            method: "POST",
            headers: { "content-type": "application/json" },
            body: JSON.stringify({
              async: true,
              tenant: "alice",
              project: "proj-a",
              goal: "hold remote active run for abandon",
              script: [
                {
                  message: "start a long command",
                  actions: [
                    {
                      toolName: "shell.exec",
                      input: { command: "sleep 1; printf done > first.txt" },
                    },
                  ],
                },
                { message: "finish", finish: true },
              ],
              verify: ["test -f first.txt"],
              skills: ["coding"],
            }),
          });
          assert.equal(create.status, 202);
          const running = await create.json();
          assert.equal(running.status, "running");

          try {
            const abandon = await fetch(`${secondBaseUrl}/tenants/alice/runs/${running.runId}/abandon?project=proj-a`, {
              method: "POST",
              headers: { "content-type": "application/json" },
              body: JSON.stringify({ reason: "wrong server cleanup" }),
            });
            assert.equal(abandon.status, 409);
            assert.match((await abandon.json()).error, /active in another server process/);

            const status = await fetch(`${secondBaseUrl}/status`);
            assert.equal(status.status, 200);
            const statusBody = await status.json();
            assert.equal(statusBody.resources.activeRuns, 1);
            assert.deepEqual(statusBody.resources.orphanedRunningRunDetails, []);

            const stillRunning = await fetch(`${firstBaseUrl}/tenants/alice/runs/${running.runId}?project=proj-a`);
            assert.equal(stillRunning.status, 200);
            assert.equal((await stillRunning.json()).status, "running");
          } finally {
            const cancel = await fetch(`${firstBaseUrl}/tenants/alice/runs/${running.runId}/cancel?project=proj-a`, {
              method: "POST",
              headers: { "content-type": "application/json" },
              body: JSON.stringify({ reason: "release remote active abandon guard" }),
            }).catch(() => undefined);
            if (cancel?.status === 200) {
              await pollJson(`${firstBaseUrl}/tenants/alice/runs/${running.runId}?project=proj-a`, (body) => body.status === "cancelled");
            } else {
              await pollJson(`${firstBaseUrl}/tenants/alice/runs/${running.runId}?project=proj-a`, (body) => body.status !== "running").catch(() => undefined);
            }
          }
        },
        { allowedTools: ["file.read", "file.write", "shell.exec", "git.diff", "verify.run"] },
      );
    },
    { allowedTools: ["file.read", "file.write", "shell.exec", "git.diff", "verify.run"] },
  );
});

test("HTTP harness applies per-run tool allowlists", async () => {
  const workspaceRoot = await tempDir("loom-http-run-policy");

  await withServer(workspaceRoot, async (baseUrl) => {
    const response = await fetch(`${baseUrl}/runs`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        tenant: "alice",
        goal: "deny shell for this run",
        allowedTools: ["file.read", "file.write", "git.diff", "verify.run"],
        script: [
          {
            message: "try shell despite global allow",
            actions: [
              {
                toolName: "shell.exec",
                input: { command: "printf denied > denied.txt" },
              },
            ],
          },
          { message: "finish", finish: true },
        ],
        verify: ["test ! -f denied.txt"],
        skills: ["coding"],
      }),
    });

    assert.equal(response.status, 201);
    const summary = await response.json();
    assert.equal(summary.status, "passed");

    const events = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/events`);
    const body = await events.json();
    const policy = body.find((event) => String(event.type) === "run_policy");
    assert.deepEqual(policy?.data.allowedTools, ["file.read", "file.write", "git.diff", "verify.run"]);
    const denied = body.find((event) => event.type === "observation" && event.data.toolName === "shell.exec");
    assert.equal(denied.data.ok, false);
    assert.match(denied.data.error, /not allowed/);
  }, { allowedTools: ["file.read", "file.write", "shell.exec", "git.diff", "verify.run"] });
});

