test("HTTP harness enforces tenant tokens when configured", async () => {
  const workspaceRoot = await tempDir("loom-http-auth");

  await withServer(
    workspaceRoot,
    async (baseUrl) => {
      const body = JSON.stringify({
        tenant: "alice",
        goal: "create auth.txt",
        script: [
          {
            message: "write auth file",
            actions: [
              {
                toolName: "file.write",
                input: { path: "auth.txt", content: "auth-ok\n" },
              },
            ],
          },
          { message: "finish", finish: true },
        ],
        verify: ["test -f auth.txt"],
        skills: ["coding"],
      });

      const missing = await fetch(`${baseUrl}/runs`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body,
      });
      assert.equal(missing.status, 401);

      const wrong = await fetch(`${baseUrl}/runs`, {
        method: "POST",
        headers: { "content-type": "application/json", authorization: "Bearer wrong" },
        body,
      });
      assert.equal(wrong.status, 401);

      const create = await fetch(`${baseUrl}/runs`, {
        method: "POST",
        headers: { "content-type": "application/json", authorization: "Bearer secret" },
        body,
      });
      assert.equal(create.status, 201);
      const summary = await create.json();
      assert.equal(summary.status, "passed");

      const listDenied = await fetch(`${baseUrl}/tenants/alice/runs`);
      assert.equal(listDenied.status, 401);

      const listAllowed = await fetch(`${baseUrl}/tenants/alice/runs`, {
        headers: { authorization: "Bearer secret" },
      });
      assert.equal(listAllowed.status, 200);
      assert.equal((await listAllowed.json()).length, 1);

      const projectsDenied = await fetch(`${baseUrl}/tenants/alice/projects`);
      assert.equal(projectsDenied.status, 401);

      const projectsAllowed = await fetch(`${baseUrl}/tenants/alice/projects`, {
        headers: { authorization: "Bearer secret" },
      });
      assert.equal(projectsAllowed.status, 200);
      assert.equal((await projectsAllowed.json()).length, 1);

      const filesDenied = await fetch(`${baseUrl}/tenants/alice/projects/default/files`);
      assert.equal(filesDenied.status, 401);

      const filesAllowed = await fetch(`${baseUrl}/tenants/alice/projects/default/files`, {
        headers: { authorization: "Bearer secret" },
      });
      assert.equal(filesAllowed.status, 200);
      assert.ok((await filesAllowed.json()).entries.some((entry) => entry.name === "auth.txt"));

      const saveDenied = await fetch(`${baseUrl}/tenants/alice/projects/default/files`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ path: "saved.txt", content: "denied\n" }),
      });
      assert.equal(saveDenied.status, 401);

      const saveQueryTokenDenied = await fetch(`${baseUrl}/tenants/alice/projects/default/files?token=secret`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ path: "query-token.txt", content: "denied\n" }),
      });
      assert.equal(saveQueryTokenDenied.status, 401);

      const saveAllowed = await fetch(`${baseUrl}/tenants/alice/projects/default/files`, {
        method: "POST",
        headers: { "content-type": "application/json", authorization: "Bearer secret" },
        body: JSON.stringify({ path: "saved.txt", content: "saved\n" }),
      });
      assert.equal(saveAllowed.status, 200);
      assert.equal(await readFile(join(workspaceRoot, "alice", "default", "saved.txt"), "utf8"), "saved\n");

      const commandDenied = await fetch(`${baseUrl}/tenants/alice/projects/default/commands`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ command: "printf denied > command-auth.txt" }),
      });
      assert.equal(commandDenied.status, 401);

      const commandAllowed = await fetch(`${baseUrl}/tenants/alice/projects/default/commands`, {
        method: "POST",
        headers: { "content-type": "application/json", authorization: "Bearer secret" },
        body: JSON.stringify({ command: "printf command-auth-ok > command-auth.txt" }),
      });
      assert.equal(commandAllowed.status, 200);
      assert.equal(await readFile(join(workspaceRoot, "alice", "default", "command-auth.txt"), "utf8"), "command-auth-ok");

      const readDenied = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}`, {
        headers: { authorization: "Bearer wrong" },
      });
      assert.equal(readDenied.status, 401);

      const statusQueryTokenDenied = await fetch(`${baseUrl}/status?token=secret`);
      assert.equal(statusQueryTokenDenied.status, 401);

      const streamAllowed = await fetch(
        `${baseUrl}/tenants/alice/runs/${summary.runId}/events/stream?token=secret`,
      );
      assert.equal(streamAllowed.status, 200);
      assert.match(await streamAllowed.text(), /"type":"finish"/);
    },
    { allowedTools: ["file.read", "file.write", "shell.exec", "git.diff", "verify.run"], tenantTokens: { alice: "secret" } },
  );
});

test("HTTP harness enforces tenant API key roles and records audit actors", async () => {
  const workspaceRoot = await tempDir("loom-http-api-key-roles");

  await withServer(
    workspaceRoot,
    async (baseUrl) => {
      const viewerCreate = await fetch(`${baseUrl}/runs`, {
        method: "POST",
        headers: { "content-type": "application/json", authorization: "Bearer viewer-key" },
        body: JSON.stringify({
          tenant: "alice",
          goal: "viewer cannot write",
          script: [{ message: "finish", finish: true }],
          verify: [],
          skills: ["coding"],
        }),
      });
      assert.equal(viewerCreate.status, 403);
      assert.match((await viewerCreate.json()).error, /requires developer/);

      const create = await fetch(`${baseUrl}/runs`, {
        method: "POST",
        headers: { "content-type": "application/json", authorization: "Bearer dev-key" },
        body: JSON.stringify({
          tenant: "alice",
          goal: "developer creates run",
          script: [{ message: "finish", finish: true }],
          verify: [],
          skills: ["coding"],
          clientId: "dash-dev",
        }),
      });
      assert.equal(create.status, 201);
      const summary = await create.json();
      assert.equal(summary.status, "passed");
      assert.deepEqual(summary.requester, { actor: "dev-user", role: "developer", clientId: "dash-dev" });
      assert.equal(JSON.stringify(summary).includes("dev-key"), false);

      const runEvents = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/events`, {
        headers: { authorization: "Bearer viewer-key" },
      });
      assert.equal(runEvents.status, 200);
      const runEventBody = await runEvents.json();
      const userMessage = runEventBody.find((event: any) => event.type === "user_message");
      assert.equal(userMessage?.data.content, "developer creates run");
      assert.equal(userMessage?.data.actor, "dev-user");
      assert.equal(userMessage?.data.role, "developer");
      assert.equal(userMessage?.data.clientId, "dash-dev");

      const replay = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/replay`, {
        headers: { authorization: "Bearer viewer-key" },
      });
      assert.equal(replay.status, 200);
      const replayBody = await replay.json();
      const replayUserMessage = replayBody.timeline.find((entry: any) => entry.type === "user_message");
      assert.equal(replayUserMessage?.actor, "dev-user");
      assert.equal(replayUserMessage?.role, "developer");
      assert.equal(replayUserMessage?.clientId, "dash-dev");

      const viewerList = await fetch(`${baseUrl}/tenants/alice/runs`, {
        headers: { authorization: "Bearer viewer-key" },
      });
      assert.equal(viewerList.status, 200);
      const viewerRuns = await viewerList.json();
      assert.equal(viewerRuns.length, 1);
      assert.deepEqual(viewerRuns[0].requester, { actor: "dev-user", role: "developer", clientId: "dash-dev" });

      const reviewSummary = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/review-summary`, {
        headers: { authorization: "Bearer viewer-key" },
      });
      assert.equal(reviewSummary.status, 200);
      assert.deepEqual((await reviewSummary.json()).requester, { actor: "dev-user", role: "developer", clientId: "dash-dev" });

      const handoffPackage = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/handoff-package`, {
        headers: { authorization: "Bearer viewer-key" },
      });
      assert.equal(handoffPackage.status, 200);
      assert.deepEqual((await handoffPackage.json()).reviewSummary.requester, { actor: "dev-user", role: "developer", clientId: "dash-dev" });

      const viewerSave = await fetch(`${baseUrl}/tenants/alice/projects/default/files`, {
        method: "POST",
        headers: { "content-type": "application/json", authorization: "Bearer viewer-key" },
        body: JSON.stringify({ path: "viewer.txt", content: "denied\n" }),
      });
      assert.equal(viewerSave.status, 403);

      const save = await fetch(`${baseUrl}/tenants/alice/projects/default/files`, {
        method: "POST",
        headers: { "content-type": "application/json", authorization: "Bearer dev-key" },
        body: JSON.stringify({ path: "dev.txt", content: "saved\n" }),
      });
      assert.equal(save.status, 200);

      const audit = await fetch(`${baseUrl}/tenants/alice/audit`, {
        headers: { authorization: "Bearer viewer-key" },
      });
      assert.equal(audit.status, 200);
      const events = await audit.json();
      assert.ok(events.some((event: any) => event.type === "run_created" && event.actor === "dev-user" && event.role === "developer" && event.data.runId === summary.runId));
      assert.ok(events.some((event: any) => event.type === "workspace_file_written" && event.actor === "dev-user" && event.role === "developer" && event.data.path === "dev.txt"));
      assert.ok(events.every((event: any) => !JSON.stringify(event).includes("dev-key") && !JSON.stringify(event).includes("viewer-key")));
    },
    {
      tenantApiKeys: {
        alice: [
          { token: "dev-key", actor: "dev-user", role: "developer" },
          { token: "viewer-key", actor: "view-user", role: "viewer" },
        ],
      },
    },
  );
});

