test("HTTP harness allows tenant auth headers in CORS preflight", async () => {
  const workspaceRoot = await tempDir("loom-http-cors");

  await withServer(workspaceRoot, async (baseUrl) => {
    const response = await fetch(`${baseUrl}/runs`, {
      method: "OPTIONS",
      headers: {
        origin: "https://loom.example",
        "access-control-request-method": "POST",
        "access-control-request-headers": "content-type, authorization, x-loom-tenant-token, last-event-id",
      },
    });

    assert.equal(response.status, 204);
    const methods = response.headers.get("access-control-allow-methods") ?? "";
    assert.match(methods, /\bPUT\b/);
    assert.match(methods, /\bDELETE\b/);
    const allowed = response.headers.get("access-control-allow-headers") ?? "";
    assert.match(allowed, /content-type/);
    assert.match(allowed, /authorization/);
    assert.match(allowed, /x-loom-tenant-token/);
    assert.match(allowed, /last-event-id/);
  });
});

test("HTTP harness can use an OpenAI-compatible model agent", async () => {
  const workspaceRoot = await tempDir("loom-http-model");
  let calls = 0;
  const modelServer = createServer(async (req, res) => {
    assert.equal(req.url, "/v1/chat/completions");
    assert.equal(req.headers.authorization, "Bearer server-key");
    await readBody(req);
    calls += 1;
    const step =
      calls === 1
        ? {
            message: "write model artifact",
            actions: [
              {
                toolName: "file.write",
                input: { path: "server-model.txt", content: "server-model-ok\n" },
              },
            ],
          }
        : { message: "finish", finish: true };
    res.writeHead(200, {
      "content-type": "application/json",
      "x-litellm-response-cost": calls === 1 ? "0.0012" : "0.0003",
    });
    res.end(JSON.stringify({
      id: `chatcmpl-${calls}`,
      model: "gateway-model",
      usage: {
        prompt_tokens: calls === 1 ? 20 : 8,
        completion_tokens: calls === 1 ? 10 : 4,
        total_tokens: calls === 1 ? 30 : 12,
      },
      choices: [{ message: { content: JSON.stringify(step) } }],
    }));
  });
  await new Promise<void>((resolve) => modelServer.listen(0, "127.0.0.1", resolve));
  const address = modelServer.address();
  assert.equal(typeof address, "object");
  assert.ok(address);

  try {
    await withServer(
      workspaceRoot,
      async (baseUrl) => {
        const response = await fetch(`${baseUrl}/runs`, {
          method: "POST",
          headers: { "content-type": "application/json" },
          body: JSON.stringify({
            tenant: "alice",
            goal: "create server-model.txt",
            model: "test-model",
            verify: ["test -f server-model.txt"],
            skills: ["coding"],
          }),
        });

        assert.equal(response.status, 201);
        const summary = await response.json();
        assert.equal(summary.status, "passed");
        assert.equal(summary.metadata.agentMode, "model");
        assert.equal(summary.metadata.model, "test-model");
        assert.deepEqual(summary.modelUsage, {
          requestCount: 2,
          promptTokens: 28,
          completionTokens: 14,
          totalTokens: 42,
          costUsd: 0.0015,
        });
        assert.equal(JSON.stringify(summary).includes("server-key"), false);
        assert.equal(calls, 2);
        assert.equal(
          await readFile(join(workspaceRoot, "alice", "default", "server-model.txt"), "utf8"),
          "server-model-ok\n",
        );

        const replayResponse = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/replay`);
        assert.equal(replayResponse.status, 200);
        const replay = await replayResponse.json();
        const usageEntry = replay.timeline.find((entry: any) => entry.type === "model_usage");
        assert.equal(usageEntry.title, "Model usage: test-model");
        assert.match(usageEntry.detail, /promptTokens=20/);
        assert.match(usageEntry.detail, /totalTokens=30/);
        assert.match(usageEntry.detail, /costUsd=0\.0012/);
        assert.equal(JSON.stringify(replay).includes("server-key"), false);

        const reviewSummary = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/review-summary`);
        assert.equal(reviewSummary.status, 200);
        assert.deepEqual((await reviewSummary.json()).modelUsage, summary.modelUsage);

        const handoffPackage = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/handoff-package`);
        assert.equal(handoffPackage.status, 200);
        assert.deepEqual((await handoffPackage.json()).reviewSummary.modelUsage, summary.modelUsage);
      },
      {
        modelBaseUrl: `http://127.0.0.1:${address.port}`,
        modelApiKey: "server-key",
      },
    );
  } finally {
    await new Promise<void>((resolve, reject) =>
      modelServer.close((error) => (error ? reject(error) : resolve())),
    );
  }
});

test("HTTP harness can use OpenAI-compatible tool-call model protocol", async () => {
  const workspaceRoot = await tempDir("loom-http-model-tool-call");
  const requestBodies: any[] = [];
  let calls = 0;
  const modelServer = createServer(async (req, res) => {
    assert.equal(req.url, "/v1/chat/completions");
    assert.equal(req.headers.authorization, "Bearer server-key");
    requestBodies.push(JSON.parse(await readBody(req)));
    calls += 1;
    const step =
      calls === 1
        ? {
            message: "write model tool-call artifact",
            plan: "exercise the model tool-call protocol",
            actions: [
              {
                toolName: "file.write",
                input: { path: "server-tool-call.txt", content: "server-tool-call-ok\n" },
              },
            ],
          }
        : { message: "finish", finish: true };
    res.writeHead(200, { "content-type": "application/json" });
    res.end(JSON.stringify({
      id: `chatcmpl-tool-${calls}`,
      model: "gateway-model",
      usage: {
        prompt_tokens: calls === 1 ? 22 : 9,
        completion_tokens: calls === 1 ? 11 : 5,
        total_tokens: calls === 1 ? 33 : 14,
      },
      choices: [
        {
          message: {
            tool_calls: [
              {
                id: `call-agent-step-${calls}`,
                type: "function",
                function: {
                  name: "agent_step",
                  arguments: JSON.stringify(step),
                },
              },
            ],
          },
        },
      ],
    }));
  });
  await new Promise<void>((resolve) => modelServer.listen(0, "127.0.0.1", resolve));
  const address = modelServer.address();
  assert.equal(typeof address, "object");
  assert.ok(address);

  try {
    await withServer(
      workspaceRoot,
      async (baseUrl) => {
        const response = await fetch(`${baseUrl}/runs`, {
          method: "POST",
          headers: { "content-type": "application/json" },
          body: JSON.stringify({
            tenant: "alice",
            goal: "create server-tool-call.txt",
            model: "test-model",
            modelProtocol: "tool-call",
            verify: ["test -f server-tool-call.txt"],
            skills: ["coding"],
          }),
        });

        assert.equal(response.status, 201);
        const summary = await response.json();
        assert.equal(summary.status, "passed");
        assert.equal(summary.metadata.agentMode, "model");
        assert.equal(summary.metadata.model, "test-model");
        assert.equal(summary.metadata.modelProtocol, "tool-call");
        assert.equal(requestBodies.length, 2);
        assert.equal(requestBodies[0].response_format, undefined);
        assert.equal(requestBodies[0].tools[0].function.name, "agent_step");
        assert.equal(requestBodies[0].tool_choice.function.name, "agent_step");
        assert.deepEqual(summary.modelUsage, {
          requestCount: 2,
          promptTokens: 31,
          completionTokens: 16,
          totalTokens: 47,
        });
        assert.equal(
          await readFile(join(workspaceRoot, "alice", "default", "server-tool-call.txt"), "utf8"),
          "server-tool-call-ok\n",
        );
      },
      {
        modelBaseUrl: `http://127.0.0.1:${address.port}`,
        modelApiKey: "server-key",
      },
    );
  } finally {
    await new Promise<void>((resolve, reject) =>
      modelServer.close((error) => (error ? reject(error) : resolve())),
    );
  }
});

