test("HTTP harness resume enforces model token limits against the original requester", async () => {
  const workspaceRoot = await tempDir("loom-http-model-resume-hard-limit");
  await mkdir(join(workspaceRoot, "alice", ".loom"), { recursive: true });
  await writeFile(
    join(workspaceRoot, "alice", ".loom", "policy.json"),
    JSON.stringify({
      schemaVersion: 1,
      limits: {
        modelProjectTotalTokenLimit: 100,
        modelRequesterTotalTokenLimit: 40,
      },
    }, null, 2) + "\n",
    "utf8",
  );

  let calls = 0;
  const modelServer = createServer(async (req, res) => {
    assert.equal(req.url, "/v1/chat/completions");
    assert.equal(req.headers.authorization, "Bearer server-key");
    await readBody(req);
    calls += 1;
    const step = calls === 1
      ? {
          message: "write first model trace",
          actions: [
            {
              toolName: "shell.exec",
              input: { command: "printf first > model-resume.txt; node -e \"setTimeout(()=>process.stdout.write('slept'),800)\"" },
            },
          ],
        }
      : { message: "finish resumed model run", finish: true };
    res.writeHead(200, { "content-type": "application/json" });
    res.end(JSON.stringify({
      id: `chatcmpl-resume-${calls}`,
      model: "gateway-model",
      usage: {
        prompt_tokens: calls === 1 ? 28 : 1,
        completion_tokens: calls === 1 ? 14 : 1,
        total_tokens: calls === 1 ? 42 : 2,
      },
      choices: [{ message: { content: JSON.stringify(step) } }],
    }));
  });
  await new Promise<void>((resolve) => modelServer.listen(0, "127.0.0.1", resolve));
  const address = modelServer.address();
  assert.equal(typeof address, "object");
  assert.ok(address);

  try {
    await withServer(
      workspaceRoot,
      async (baseUrl) => {
        const create = await fetch(`${baseUrl}/runs`, {
          method: "POST",
          headers: { "content-type": "application/json", authorization: "Bearer dev-a-key" },
          body: JSON.stringify({
            async: true,
            tenant: "alice",
            project: "proj-a",
            goal: "pause model run before resume budget check",
            model: "test-model",
            allowedTools: ["shell.exec", "verify.run"],
            verify: ["test -f model-resume.txt"],
            skills: ["coding"],
            clientId: "dev-a-tab",
          }),
        });
        assert.equal(create.status, 202);
        const running = await create.json();

        for (let attempt = 0; attempt < 60; attempt += 1) {
          const events = await fetch(`${baseUrl}/tenants/alice/runs/${running.runId}/events?project=proj-a`, {
            headers: { authorization: "Bearer dev-b-key" },
          });
          if (events.status === 200) {
            const body = await events.json();
            if (body.some((event: any) => event.type === "action")) break;
          }
          await new Promise((resolve) => setTimeout(resolve, 25));
        }

        const pause = await fetch(`${baseUrl}/tenants/alice/runs/${running.runId}/comments?project=proj-a`, {
          method: "POST",
          headers: { "content-type": "application/json", authorization: "Bearer dev-b-key" },
          body: JSON.stringify({ message: "Pause before budgeted resume.", pause: true, clientId: "dev-b-tab" }),
        });
        assert.equal(pause.status, 201);

        let paused: any;
        for (let attempt = 0; attempt < 80; attempt += 1) {
          const response = await fetch(`${baseUrl}/tenants/alice/runs/${running.runId}?project=proj-a`, {
            headers: { authorization: "Bearer dev-b-key" },
          });
          assert.equal(response.status, 200);
          paused = await response.json();
          if (paused.status === "paused") break;
          await new Promise((resolve) => setTimeout(resolve, 50));
        }
        assert.equal(paused.status, "paused");
        assert.deepEqual(paused.requester, { actor: "dev-a", role: "developer", clientId: "dev-a-tab" });
        assert.equal(paused.modelUsage.totalTokens, 42);

        let tenantStatus: any;
        for (let attempt = 0; attempt < 40; attempt += 1) {
          const response = await fetch(`${baseUrl}/tenants/alice/status`, {
            headers: { authorization: "Bearer dev-b-key" },
          });
          assert.equal(response.status, 200);
          tenantStatus = await response.json();
          if (tenantStatus.resources.activeRuns === 0) break;
          await new Promise((resolve) => setTimeout(resolve, 25));
        }
        assert.equal(tenantStatus.resources.activeRuns, 0);

        const resume = await fetch(`${baseUrl}/tenants/alice/runs/${running.runId}/resume?project=proj-a`, {
          method: "POST",
          headers: { "content-type": "application/json", authorization: "Bearer dev-b-key" },
          body: JSON.stringify({ clientId: "dev-b-resume-tab" }),
        });
        assert.equal(resume.status, 409);
        assert.match((await resume.json()).error, /requester model token limit exceeded for dev-a: 42 >= 40/);
        assert.equal(calls, 1);
      },
      {
        allowedTools: ["file.read", "file.write", "git.diff", "git.commit", "verify.run", "shell.exec"],
        modelBaseUrl: `http://127.0.0.1:${address.port}`,
        modelApiKey: "server-key",
        tenantApiKeys: {
          alice: [
            { token: "dev-a-key", actor: "dev-a", role: "developer" },
            { token: "dev-b-key", actor: "dev-b", role: "developer" },
          ],
        },
      },
    );
  } finally {
    await new Promise<void>((resolve, reject) =>
      modelServer.close((error) => (error ? reject(error) : resolve())),
    );
  }
});

test("HTTP harness replay exposes model agent diagnostics", async () => {
  const workspaceRoot = await tempDir("loom-http-model-diagnostics");
  const rawContent = `not json ${"x".repeat(2600)}`;
  const modelServer = createServer(async (req, res) => {
    assert.equal(req.url, "/v1/chat/completions");
    assert.equal(req.headers.authorization, "Bearer server-key");
    await readBody(req);
    res.writeHead(200, { "content-type": "application/json" });
    res.end(JSON.stringify({ choices: [{ message: { content: rawContent } }] }));
  });
  await new Promise<void>((resolve) => modelServer.listen(0, "127.0.0.1", resolve));
  const address = modelServer.address();
  assert.equal(typeof address, "object");
  assert.ok(address);

  try {
    await withServer(
      workspaceRoot,
      async (baseUrl) => {
        const response = await fetch(`${baseUrl}/runs`, {
          method: "POST",
          headers: { "content-type": "application/json" },
          body: JSON.stringify({
            tenant: "alice",
            goal: "surface model diagnostics",
            model: "test-model",
            verify: [],
          }),
        });

        assert.equal(response.status, 201);
        const summary = await response.json();
        assert.equal(summary.status, "error");
        assert.equal(summary.error.kind, "model_agent_protocol");
        assert.equal(summary.error.details.model, "test-model");
        assert.equal(summary.error.details.responseExcerpt.length, 2003);
        assert.equal(JSON.stringify(summary).includes("server-key"), false);

        const replayResponse = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/replay`);
        assert.equal(replayResponse.status, 200);
        const replay = await replayResponse.json();
        const errorEntry = replay.timeline.find((entry: any) => entry.type === "error");
        assert.match(errorEntry?.detail, /model response was not valid JSON/);
        assert.match(errorEntry?.detail, /kind=model_agent_protocol/);
        assert.match(errorEntry?.detail, /responseExcerpt.*not json/);
        assert.equal(JSON.stringify(replay).includes("server-key"), false);

        const reviewSummaryResponse = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/review-summary`);
        assert.equal(reviewSummaryResponse.status, 200);
        const reviewSummary = await reviewSummaryResponse.json();
        assert.equal(reviewSummary.error.kind, "model_agent_protocol");
        assert.equal(reviewSummary.error.details.model, "test-model");
        assert.equal(reviewSummary.error.details.responseExcerpt.length, 160);
        assert.equal(JSON.stringify(reviewSummary).includes("server-key"), false);

        const handoffPackageResponse = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/handoff-package`);
        assert.equal(handoffPackageResponse.status, 200);
        const handoffPackage = await handoffPackageResponse.json();
        assert.equal(handoffPackage.reviewSummary.error.kind, "model_agent_protocol");
        assert.equal(handoffPackage.reviewSummary.error.details.responseExcerpt.length, 160);
        assert.equal(JSON.stringify(handoffPackage).includes("server-key"), false);
      },
      {
        modelBaseUrl: `http://127.0.0.1:${address.port}`,
        modelApiKey: "server-key",
      },
    );
  } finally {
    await new Promise<void>((resolve, reject) =>
      modelServer.close((error) => (error ? reject(error) : resolve())),
    );
  }
});

test("HTTP harness replay exposes model agent repair retries", async () => {
  const workspaceRoot = await tempDir("loom-http-model-retry-replay");
  let calls = 0;
  const modelServer = createServer(async (req, res) => {
    assert.equal(req.url, "/v1/chat/completions");
    assert.equal(req.headers.authorization, "Bearer server-key");
    await readBody(req);
    calls += 1;
    res.writeHead(200, { "content-type": "application/json" });
    res.end(
      JSON.stringify({
        choices: [
          {
            message: {
              content: calls === 1
                ? "not json"
                : JSON.stringify({ message: "recovered after retry", finish: true }),
            },
          },
        ],
      }),
    );
  });
  await new Promise<void>((resolve) => modelServer.listen(0, "127.0.0.1", resolve));
  const address = modelServer.address();
  assert.equal(typeof address, "object");
  assert.ok(address);

  try {
    await withServer(
      workspaceRoot,
      async (baseUrl) => {
        const response = await fetch(`${baseUrl}/runs`, {
          method: "POST",
          headers: { "content-type": "application/json" },
          body: JSON.stringify({
            tenant: "alice",
            goal: "recover model protocol error",
            model: "test-model",
            verify: [],
          }),
        });

        assert.equal(response.status, 201);
        const summary = await response.json();
        assert.equal(summary.status, "passed");
        assert.equal(calls, 2);

        const replayResponse = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/replay`);
        assert.equal(replayResponse.status, 200);
        const replay = await replayResponse.json();
        const retryEntry = replay.timeline.find((entry: any) => entry.type === "agent_retry");
        assert.equal(retryEntry?.title, "Agent retry: model_agent_protocol");
        assert.match(retryEntry?.detail, /model response was not valid JSON/);
        assert.match(retryEntry?.detail, /attempt=1/);
        assert.match(retryEntry?.detail, /nextAttempt=2/);
        assert.match(retryEntry?.detail, /responseExcerpt=not json/);
        assert.equal(JSON.stringify(replay).includes("server-key"), false);
      },
      {
        modelBaseUrl: `http://127.0.0.1:${address.port}`,
        modelApiKey: "server-key",
      },
    );
  } finally {
    await new Promise<void>((resolve, reject) =>
      modelServer.close((error) => (error ? reject(error) : resolve())),
    );
  }
});

test("HTTP harness can use tenant policy model key envs", async () => {
  const workspaceRoot = await tempDir("loom-http-tenant-model");
  const previous = process.env.LOOM_ALICE_MODEL_KEY;
  process.env.LOOM_ALICE_MODEL_KEY = "alice-model-key";
  const callsByAuth = new Map<string, number>();
  const modelServer = createServer(async (req, res) => {
    assert.equal(req.url, "/v1/chat/completions");
    const authorization = req.headers.authorization ?? "";
    assert.ok(authorization === "Bearer alice-model-key" || authorization === "Bearer server-key");
    await readBody(req);
    const calls = (callsByAuth.get(authorization) ?? 0) + 1;
    callsByAuth.set(authorization, calls);
    const isAlice = authorization === "Bearer alice-model-key";
    const step =
      calls === 1
        ? {
            message: "write tenant model artifact",
            actions: [
              {
                toolName: "file.write",
                input: {
                  path: isAlice ? "alice-model.txt" : "bob-model.txt",
                  content: isAlice ? "alice-model-ok\n" : "bob-model-ok\n",
                },
              },
            ],
          }
        : { message: "finish", finish: true };
    res.writeHead(200, { "content-type": "application/json" });
    res.end(JSON.stringify({ choices: [{ message: { content: JSON.stringify(step) } }] }));
  });
  await new Promise<void>((resolve) => modelServer.listen(0, "127.0.0.1", resolve));
  const address = modelServer.address();
  assert.equal(typeof address, "object");
  assert.ok(address);

  try {
    await withServer(
      workspaceRoot,
      async (baseUrl) => {
        const policy = await fetch(`${baseUrl}/tenants/alice/policy`, {
          method: "PUT",
          headers: { "content-type": "application/json" },
          body: JSON.stringify({ schemaVersion: 1, modelKeyEnv: "LOOM_ALICE_MODEL_KEY" }),
        });
        assert.equal(policy.status, 200);
        const sanitizedPolicy = await policy.json();
        assert.equal(sanitizedPolicy.modelKeyEnv, "LOOM_ALICE_MODEL_KEY");
        assert.equal(JSON.stringify(sanitizedPolicy).includes("alice-model-key"), false);

        const alice = await fetch(`${baseUrl}/runs`, {
          method: "POST",
          headers: { "content-type": "application/json" },
          body: JSON.stringify({
            tenant: "alice",
            goal: "create alice-model.txt",
            model: "test-model",
            verify: ["test -f alice-model.txt"],
            skills: ["coding"],
          }),
        });
        assert.equal(alice.status, 201);
        assert.equal((await alice.json()).status, "passed");

        const bob = await fetch(`${baseUrl}/runs`, {
          method: "POST",
          headers: { "content-type": "application/json" },
          body: JSON.stringify({
            tenant: "bob",
            goal: "create bob-model.txt",
            model: "test-model",
            verify: ["test -f bob-model.txt"],
            skills: ["coding"],
          }),
        });
        assert.equal(bob.status, 201);
        assert.equal((await bob.json()).status, "passed");

        assert.equal(callsByAuth.get("Bearer alice-model-key"), 2);
        assert.equal(callsByAuth.get("Bearer server-key"), 2);
        assert.equal(
          await readFile(join(workspaceRoot, "alice", "default", "alice-model.txt"), "utf8"),
          "alice-model-ok\n",
        );
        assert.equal(
          await readFile(join(workspaceRoot, "bob", "default", "bob-model.txt"), "utf8"),
          "bob-model-ok\n",
        );
      },
      {
        modelBaseUrl: `http://127.0.0.1:${address.port}`,
        modelApiKey: "server-key",
      },
    );
  } finally {
    if (previous === undefined) delete process.env.LOOM_ALICE_MODEL_KEY;
    else process.env.LOOM_ALICE_MODEL_KEY = previous;
    await new Promise<void>((resolve, reject) =>
      modelServer.close((error) => (error ? reject(error) : resolve())),
    );
  }
});

