test("HTTP harness can attach a created pull request and hold for human review", async () => {
  const workspaceRoot = await tempDir("loom-http-pr");
  const pullRequests: Array<{ issue?: string; branch?: string; baseBranch?: string; status?: string }> = [];

  await withServer(
    workspaceRoot,
    async (baseUrl) => {
      const response = await fetch(`${baseUrl}/runs`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({
          tenant: "alice",
          project: "proj-a",
          repo: "https://git.example/team/proj-a.git",
          branch: "task/42",
          baseBranch: "main",
          issue: "team/proj-a#42",
          pullRequest: true,
          reviewRequired: true,
          goal: "create pr.txt",
          script: [
            {
              message: "write pr file",
              actions: [
                {
                  toolName: "file.write",
                  input: { path: "pr.txt", content: "review me\n" },
                },
              ],
            },
            { message: "finish", finish: true },
          ],
          verify: ["test -f pr.txt"],
          skills: ["coding"],
          clientId: "dash-pr-run",
        }),
      });

      assert.equal(response.status, 201);
      const summary = await response.json();
      assert.equal(summary.status, "review_required");
      assert.deepEqual(summary.review, { required: true, status: "pending" });
      assert.equal(summary.metadata.pullRequestIndex, 9);
      assert.equal(summary.metadata.pullRequestUrl, "https://git.example/team/proj-a/pulls/9");

      const readSummary = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}?project=proj-a`);
      assert.equal(readSummary.status, 200);
      const savedSummary = await readSummary.json();
      assert.equal(savedSummary.metadata.pullRequestUrl, "https://git.example/team/proj-a/pulls/9");

      const events = await fetch(`${baseUrl}/tenants/alice/runs/${summary.runId}/events?project=proj-a`);
      assert.equal(events.status, 200);
      const body = await events.json();
      assert.ok(body.some((event) =>
        event.type === "external_effect" &&
        event.data.kind === "pull_request" &&
        event.data.issueUrl === "https://git.example/team/proj-a/issues/42" &&
        event.data.dashboardUrl === `https://loom.example/?tenant=alice&project=proj-a&runId=${summary.runId}` &&
        event.data.summaryUrl === `https://loom.example/tenants/alice/runs/${summary.runId}?project=proj-a` &&
        event.data.reviewSummaryUrl === `https://loom.example/tenants/alice/runs/${summary.runId}/review-summary?project=proj-a` &&
        event.data.handoffPackageUrl === `https://loom.example/tenants/alice/runs/${summary.runId}/handoff-package?project=proj-a` &&
        event.data.handoffFollowupsUrl === `https://loom.example/tenants/alice/runs/${summary.runId}/handoff-runs?project=proj-a` &&
        event.data.pullRequestIndex === 9 &&
        event.data.pullRequestUrl === "https://git.example/team/proj-a/pulls/9" &&
        event.data.requester?.clientId === "dash-pr-run",
      ));
    },
    {
      issueBaseUrl: "https://git.example",
      publicUrl: "https://loom.example",
      pullRequestReporter: async (summary: { metadata?: { issue?: string; branch?: string; baseBranch?: string }; status?: string }) => {
        pullRequests.push({
          issue: summary.metadata?.issue,
          branch: summary.metadata?.branch,
          baseBranch: summary.metadata?.baseBranch,
          status: summary.status,
        });
        return { index: 9, url: "https://git.example/team/proj-a/pulls/9" };
      },
    },
  );

  assert.deepEqual(pullRequests, [
    {
      issue: "team/proj-a#42",
      branch: "task/42",
      baseBranch: "main",
      status: "review_required",
    },
  ]);
});

