test("HTTP harness can approve a review-gated run and merge its pull request", async () => {
  const workspaceRoot = await tempDir("loom-http-review-approve");
  const merges: Array<{ runId: string; pullRequestIndex?: number; note?: string }> = [];

  await withServer(
    workspaceRoot,
    async (baseUrl) => {
      const create = await fetch(`${baseUrl}/runs`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({
          tenant: "alice",
          project: "proj-a",
          branch: "task/42",
          issue: "team/proj-a#42",
          pullRequest: true,
          reviewRequired: true,
          goal: "create approved.txt",
          script: [
            {
              message: "write approved file",
              actions: [
                {
                  toolName: "file.write",
                  input: { path: "approved.txt", content: "approved\n" },
                },
              ],
            },
            { message: "finish", finish: true },
          ],
          verify: ["test -f approved.txt"],
          skills: ["coding"],
        }),
      });
      assert.equal(create.status, 201);
      const created = await create.json();
      assert.equal(created.status, "review_required");

      const review = await fetch(`${baseUrl}/tenants/alice/runs/${created.runId}/review?project=proj-a`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({
          decision: "approved",
          note: "Looks good.",
          merge: true,
        }),
      });
      assert.equal(review.status, 200);
      const reviewed = await review.json();
      assert.equal(reviewed.status, "passed");
      assert.deepEqual(reviewed.review, {
        required: true,
        status: "approved",
        note: "Looks good.",
        merged: true,
      });

      const events = await fetch(`${baseUrl}/tenants/alice/runs/${created.runId}/events?project=proj-a`);
      assert.equal(events.status, 200);
      const body = await events.json();
      assert.ok(body.some((event) => event.type === "review_gate" && event.data.status === "approved"));
      assert.ok(body.some((event) => event.type === "finish" && event.data.status === "passed"));
      assert.ok(body.some((event) =>
        event.type === "external_effect" &&
        event.data.kind === "pull_request_merge" &&
        event.data.issueUrl === "https://git.example/team/proj-a/issues/42" &&
        event.data.pullRequestIndex === 9,
      ));
    },
    {
      issueBaseUrl: "https://git.example",
      pullRequestReporter: async () => ({ index: 9, url: "https://git.example/team/proj-a/pulls/9" }),
      mergeReporter: async (summary: { runId: string; metadata?: { pullRequestIndex?: number } }, note?: string) => {
        merges.push({
          runId: summary.runId,
          pullRequestIndex: summary.metadata?.pullRequestIndex,
          note,
        });
      },
    },
  );

  assert.equal(merges.length, 1);
  assert.equal(merges[0].pullRequestIndex, 9);
  assert.equal(merges[0].note, "Looks good.");
});

