async function pollJson(url: string, done: (body: any) => boolean, init?: RequestInit, timeoutMs = 5_000): Promise<any> {
  const deadline = Date.now() + timeoutMs;
  while (Date.now() < deadline) {
    const response = await fetch(url, init);
    const text = await response.text();
    assert.equal(response.status, 200, text);
    const body = JSON.parse(text);
    if (done(body)) return body;
    await new Promise((resolve) => setTimeout(resolve, 50));
  }
  throw new Error(`timed out polling ${url}`);
}

async function pollMissingFile(path: string): Promise<void> {
  const deadline = Date.now() + 5_000;
  while (Date.now() < deadline) {
    try {
      await readFile(path, "utf8");
    } catch (error) {
      if (error && typeof error === "object" && "code" in error && error.code === "ENOENT") return;
      throw error;
    }
    await new Promise((resolve) => setTimeout(resolve, 50));
  }
  throw new Error(`timed out waiting for missing file ${path}`);
}

async function pollReady(url: string): Promise<any> {
  const deadline = Date.now() + 5_000;
  while (Date.now() < deadline) {
    const response = await fetch(url);
    const text = await response.text();
    assert.ok(response.status === 200 || response.status === 503, text);
    const body = JSON.parse(text);
    if (response.status === 200 && body.ready === true) return body;
    await new Promise((resolve) => setTimeout(resolve, 50));
  }
  throw new Error(`timed out polling ${url}`);
}

async function readBody(req: IncomingMessage): Promise<string> {
  const chunks: Buffer[] = [];
  for await (const chunk of req) {
    chunks.push(Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk));
  }
  return Buffer.concat(chunks).toString("utf8");
}

async function writeRunningStatus(
  workspaceRoot: string,
  tenant: string,
  project: string,
  runId: string,
  lease: { heartbeatAt?: string; leaseExpiresAt?: string } = {},
): Promise<void> {
  await writeProjectRegistration(workspaceRoot, tenant, project);
  const runDir = join(workspaceRoot, tenant, project, ".loom", "runs", runId);
  await mkdir(runDir, { recursive: true });
  await writeFile(
    join(runDir, "status.json"),
    JSON.stringify({
      runId,
      tenant,
      project,
      goal: "persisted running run",
      status: "running",
      skills: ["coding"],
      startedAt: "2026-06-26T00:00:00.000Z",
      ...lease,
      runDir,
    }, null, 2) + "\n",
    "utf8",
  );
}

async function writeRunSummary(
  workspaceRoot: string,
  tenant: string,
  project: string,
  runId: string,
  overrides: Record<string, unknown> = {},
): Promise<void> {
  await writeProjectRegistration(workspaceRoot, tenant, project);
  const runDir = join(workspaceRoot, tenant, project, ".loom", "runs", runId);
  await mkdir(runDir, { recursive: true });
  await writeFile(
    join(runDir, "summary.json"),
    JSON.stringify({
      runId,
      tenant,
      project,
      goal: "persisted run summary",
      status: "passed",
      skills: ["coding"],
      metadata: { tenant, project },
      startedAt: "2026-06-26T00:00:00.000Z",
      endedAt: "2026-06-26T00:00:01.000Z",
      eventCount: 1,
      runDir,
      verification: null,
      ...overrides,
    }, null, 2) + "\n",
    "utf8",
  );
}

async function writeQueuedStatus(
  workspaceRoot: string,
  tenant: string,
  project: string,
  runId: string,
  request: Record<string, unknown>,
): Promise<void> {
  await writeProjectRegistration(workspaceRoot, tenant, project);
  const runDir = join(workspaceRoot, tenant, project, ".loom", "runs", runId);
  await mkdir(runDir, { recursive: true });
  await writeFile(
    join(runDir, "status.json"),
    JSON.stringify({
      runId,
      tenant,
      project,
      goal: request.goal,
      status: "queued",
      skills: request.skills,
      metadata: { tenant, project },
      queuedAt: "2026-06-26T00:00:00.000Z",
      runDir,
    }, null, 2) + "\n",
    "utf8",
  );
  await writeFile(
    join(runDir, "queued-request.json"),
    JSON.stringify({ schemaVersion: 1, request }, null, 2) + "\n",
    "utf8",
  );
}

function fakeSessionExecutor(calls: string[], runId: string): any {
  return {
    async prepare(): Promise<void> {
      calls.push("prepare");
    },
    async inspectPath(path: string): Promise<any> {
      return { path, kind: "missing" };
    },
    async readFile(): Promise<string> {
      return "";
    },
    async writeFile(): Promise<void> {},
    async runCommand(): Promise<{ stdout: string; stderr: string; exitCode: number }> {
      return { stdout: "", stderr: "", exitCode: 0 };
    },
    startSession(command: string): any {
      calls.push(`start:${runId}:${command}`);
      const outputListeners: Array<(event: { stream: "stdout" | "stderr"; data: string }) => void> = [];
      const exitListeners: Array<(event: { exitCode: number }) => void> = [];
      setTimeout(() => {
        for (const listener of outputListeners) listener({ stream: "stdout", data: "ready\n" });
      }, 0);
      return {
        onOutput(listener: (event: { stream: "stdout" | "stderr"; data: string }) => void): () => void {
          outputListeners.push(listener);
          return () => undefined;
        },
        onExit(listener: (event: { exitCode: number }) => void): () => void {
          exitListeners.push(listener);
          return () => undefined;
        },
        async write(input: string): Promise<void> {
          calls.push(`write:${runId}:${input}`);
          for (const listener of outputListeners) listener({ stream: "stdout", data: `echo:${input}` });
          if (input.trim() === "exit") {
            for (const listener of exitListeners) listener({ exitCode: 0 });
          }
        },
        async stop(): Promise<void> {
          calls.push(`stop:${runId}`);
          for (const listener of exitListeners) listener({ exitCode: 0 });
        },
      };
    },
  };
}

function escapeRegExp(value: string): string {
  return value.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}
